                            <img src="https://p16-common-sign.tiktokcdn-us.com/tos-maliva-avt-0068/7e2e1371cfbf83e74c82220a11b83800~tplv-tiktokx-cropcenter:720:720.jpeg?dr=9640&refresh_token=09169c01&x-expires=1769184000&x-signature=NjBhAaA%2FAZBQcvni%2Fvv5cwFblcs%3D&t=4d5b0474&ps=13740610&shp=a5d48078&shcp=81f88b70&idc=useast5" alt="Carlos Souza">
