                </section>
            </div>
        </main>
    </div>

    <div class="sticky-cta" id="stickyCta">
        <a href="/regula" class="btn-primary">
            <i class="fas fa-id-card mr-2"></i> Regularizar Agora
        </a>
    </div>

    <footer class="footer">
