<body>
    <div class="main-wrapper">
        <header class="header">
            <div class="logo-container">
                <img src="https://cdn-icons-png.flaticon.com/512/197/197386.png" alt="EdocBr Logo" class="logo">
                <span class="brand-name">Título EdocBr</span>
            </div>
            <button class="mobile-menu-btn" id="mobileMenuBtn">
                <i class="fas fa-bars"></i>
            </button>
            <nav class="nav-menu" id="navMenu">
                <ul>
                    <li><a href="/">Voltar ao Início</a></li>
                </ul>
            </nav>
        </header>

        <main class="main-content">
            <div class="container">
                <h1 class="section-title">Solicitação de e-Doc Tipo: Regularizar Título</h1>

                <!-- Step 1: Cidade Natal e Estado -->
                <div class="step active" id="step1">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Informações Iniciais</h2>
                    <div class="address-field">
                        <label for="cidadeNatalInput" class="block text-xs font-medium text-gray-700 mb-1">Cidade Natal *</label>
                        <input type="text" id="cidadeNatalInput" placeholder="Digite sua cidade natal" class="input-field" required>
                    </div>
                    <div class="address-field">
                        <label for="estadoVotoInput" class="block text-xs font-medium text-gray-700 mb-1">Estado onde exerce voto *</label>
                        <select id="estadoVotoInput" class="select-field" required>
                            <option value="">Selecione o estado</option>
                            <option value="AC">Acre (AC)</option>
                            <option value="AL">Alagoas (AL)</option>
                            <option value="AP">Amapá (AP)</option>
                            <option value="AM">Amazonas (AM)</option>
                            <option value="BA">Bahia (BA)</option>
                            <option value="CE">Ceará (CE)</option>
