        .btn-secondary:hover {
            background: #4b5563;
            transform: translateY(-2px);
            box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
        }
        .input-field, .select-field {
            width: 100%;
            padding: 0.7rem;
            border: 1px solid #d1d5db;
            border-radius: 6px;
            font-size: 0.9rem;
            margin-bottom: 0.5rem;
            transition: all 0.3s ease;
            background: #f9fafb;
        }
        .input-field:focus, .select-field:focus {
            outline: none;
            border-color: var(--primary-color);
            box-shadow: 0 0 0 2px rgba(2, 125, 108, 0.15);
        }
        .input-field:disabled {
            background: #f3f4f6;
            color: #6b7280;
        }
        .radio-field {
            display: flex;
            align-items: center;
            margin-bottom: 0.4rem;
            gap: 0.4rem;
        }
        .radio-field input[type="radio"] {
            accent-color: var(--primary-color);
            width: 1rem;
            height: 1rem;
        }
        .radio-field label {
            font-size: 0.9rem;
            color: var(--text-color);
        }
        .preview-box {
            border: 1px solid #e5e7eb;
            border-radius: 6px;
            padding: 1rem;
            background: #f9fafb;
            margin-bottom: 0.75rem;
            transition: all 0.3s ease;
        }
        .preview-box:hover {
            border-color: var(--accent-color);
        }
        .preview-box div {
            margin-bottom: 0.4rem;
            color: var(--text-color);
            font-size: 0.9rem;
        }
        .progress-bar {
            display: flex;
            justify-content: center;
            align-items: center;
            gap: 0.4rem;
            margin-bottom: 1rem;
        }
        .progress-step {
            width: 28px;
            height: 28px;
            background: #e5e7eb;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            color: #6b7280;
            font-weight: 600;
            font-size: 0.85rem;
            transition: all 0.3s ease;
        }
        .progress-step.active {
            background: var(--primary-color);
            color: white;
            transform: scale(1.1);
        }
        .progress-line {
            width: 40px;
            height: 3px;
            background: #e5e7eb;
            border-radius: 2px;
            transition: all 0.3s ease;
        }
        .progress-line.active {
            background: var(--primary-color);
        }
        .spinner {
            border: 3px solid #f3f4f6;
            border-top: 3px solid var(--primary-color);
            border-radius: 50%;
            width: 28px;
            height: 28px;
            animation: spin 1s linear infinite;
            margin: 0.75rem auto;
        }
        @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
        }
        .error {
            color: #dc2626;
            font-weight: 600;
            font-size: 0.8rem;
        }
        .success {
            color: var(--primary-color);
            font-weight: 600;
            font-size: 0.8rem;
        }
        .step {
            display: none;
        }
        .step.active {
            display: block;
            animation: fadeIn 0.5s ease-in;
        }
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(10px); }
            to { opacity: 1; transform: translateY(0); }
        }
        .footer {
            background: linear-gradient(135deg, var(--primary-color), var(--dark-color));
            color: white;
            padding: 1.5rem 0.75rem;
            text-align: center;
            width: 100%;
            border-top-left-radius: 10px;
            border-top-right-radius: 10px;
