            margin-top: 0.75rem;
            font-size: 0.8rem;
            color: #d1fae5;
        }
        .address-field {
            margin-bottom: 0.5rem;
        }
        .address-field label {
            display: block;
            margin-bottom: 0.4rem;
            font-weight: 600;
            color: var(--text-color);
            font-size: 0.9rem;
        }
        .address-grid {
            display: grid;
            gap: 0.5rem;
        }
        .loading-container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 0.4rem;
        }
        .loading-text {
            font-weight: 600;
            color: var(--primary-color);
            font-size: 0.9rem;
        }
        .btn-group {
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
            justify-content: center;
        }
        @media (min-width: 768px) {
            .header {
                padding: 1rem 1.5rem;
            }
            .mobile-menu-btn {
                display: none;
            }
            .nav-menu {
                position: static;
                background: transparent;
                transform: none;
                flex-direction: row;
                justify-content: flex-end;
                padding: 0;
            }
            .nav-menu ul {
                flex-direction: row;
                gap: 1.5rem;
                width: auto;
            }
            .nav-menu ul li a {
                font-size: 0.9rem;
            }
            .main-content {
                padding: 2.5rem 1rem;
            }
            .container {
                padding: 2rem;
                border-radius: 12px;
                max-width: 720px;
            }
            .section-title {
                font-size: 1.8rem;
            }
            .btn-primary {
                padding: 0.875rem 2rem;
