                font-size: 1rem;
            }
            .btn-group {
                flex-direction: row;
                gap: 1rem;
            }
            .btn-group .btn-primary, .btn-group .btn-secondary {
                width: auto;
                flex: 1;
                max-width: 180px;
            }
            .address-grid {
                grid-template-columns: 1fr 2fr;
            }
            .progress-step {
                width: 32px;
