            }
            .preview-box {
                padding: 1.25rem;
                font-size: 0.95rem;
            }
            .preview-box div {
                font-size: 0.95rem;
            }
        }
    </style>
</head>
<body>
    <div class="main-wrapper">
        <header class="header">
            <div class="logo-container">
