                <div class="step active" id="step1">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Verificação de Dados</h2>
                    <div class="address-field">
                        <label for="cpfInput" class="block text-xs font-medium text-gray-700 mb-1">Digite o seu CPF *</label>
                        <input type="text" id="cpfInput" placeholder="000.000.000-00" class="input-field" maxlength="14" required>
