        .btn-next:active { transform: scale(0.98); }
        .btn-back {
            color: #64748b;
            font-size: 0.9rem;
            font-weight: 600;
            margin-top: 1rem;
            text-align: center;
            width: 100%;
            display: block;
            text-decoration: none;
            cursor: pointer;
        }
        .input-large {
            width: 100%;
            border: 2px solid #e2e8f0;
            border-radius: 8px;
            padding: 1rem;
            font-size: 1.1rem;
            margin-top: 1rem;
            outline: none;
            transition: border-color 0.2s;
        }
        .input-large:focus { border-color: var(--primary-color); }

        /* Barra de progresso melhorada */
        .progress-container {
            margin-bottom: 2rem;
        }
        .progress-mini {
            height: 8px;
            background: #e2e8f0;
            border-radius: 10px;
            overflow: hidden;
            position: relative;
