        .progress-inner {
            height: 100%;
            background: linear-gradient(90deg, var(--primary-color), var(--secondary-color));
            width: 0%;
            transition: width 0.4s cubic-bezier(0.4, 0, 0.2, 1);
            position: relative;
        }
        .progress-inner::after {
            content: '';
            position: absolute;
            top: 0;
            right: 0;
            bottom: 0;
            left: 0;
            background: linear-gradient(90deg, transparent, rgba(255,255,255,0.3), transparent);
            animation: shimmer 2s infinite;
        }
        @keyframes shimmer {
            0% { transform: translateX(-100%); }
            100% { transform: translateX(100%); }
        }
        .progress-text {
            text-align: center;
            margin-top: 0.5rem;
            font-size: 0.85rem;
            font-weight: 600;
            color: var(--primary-color);
        }

        .label-main {
            font-size: 1.3rem;
            font-weight: 800;
            color: #0f172a;
            line-height: 1.3;
        }
        .radio-option {
            border: 2px solid #e2e8f0;
            border-radius: 8px;
            padding: 1rem;
            margin-top: 0.75rem;
            display: flex;
            align-items: center;
            gap: 1rem;
            cursor: pointer;
            font-weight: 600;
            transition: all 0.2s;
        }
        .radio-option:hover {
            border-color: #cbd5e1;
            background: #f8fafc;
        }
        .radio-option.selected {
            border-color: var(--primary-color);
            background: #f0fdfa;
        }
        .spinner {
            border: 4px solid #f1f5f9;
            border-top: 4px solid var(--primary-color);
            border-radius: 50%;
            width: 40px;
            height: 40px;
            animation: spin 1s linear infinite;
            margin: 2rem auto;
        }
        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
        .preview-item {
            display: flex;
            justify-content: space-between;
            padding: 0.75rem 0;
            border-bottom: 1px solid #f1f5f9;
            font-size: 0.95rem;
        }
        .preview-label { color: #64748b; font-weight: 500; }
        .preview-value { color: #0f172a; font-weight: 700; text-align: right; }
        .footer {
            background: linear-gradient(135deg, var(--primary-color), var(--dark-color));
            color: white;
            padding: 1.5rem 0.75rem;
            text-align: center;
            width: 100%;
            border-top-left-radius: 10px;
            border-top-right-radius: 10px;
            margin-top: 3rem;
        }
        .footer a {
            color: var(--light-color);
            text-decoration: underline;
            transition: color 0.3s ease;
        }
        .footer a:hover {
            color: white;
        }
        .copyright {
            margin-top: 0.75rem;
            font-size: 0.8rem;
            color: #d1fae5;
        }
        .input-row {
            display: grid;
            grid-template-columns: 1fr 1fr;
            gap: 0.75rem;
        }
        .input-small {
            width: 100%;
            border: 2px solid #e2e8f0;
            border-radius: 8px;
            padding: 1rem;
            font-size: 1rem;
            outline: none;
            transition: border-color 0.2s;
        }
        .input-small:focus { border-color: var(--primary-color); }
        @media (min-width: 768px) {
            .header {
