                    <div class="info-message">
                        <p><strong>Segurança dos seus dados</strong></p>
                        <p>Para continuar a análise, precisamos validar seus dados. O CPF é usado exclusivamente para consulta e não é armazenado.</p>
                    </div>

                    <div class="checkbox-field">
                        <input type="checkbox" id="aceitoTermos" required>
                        <label for="aceitoTermos">Li e aceito os termos de uso. Entendo que meus dados serão utilizados apenas para validação e não serão armazenados.</label>
                    </div>

                    <button onclick="validarTipoVia()" class="btn-primary">
                        <i class="fas fa-check mr-2"></i> Entendi e aceito
                    </button>
                    <button onclick="voltarStep(1)" class="btn-secondary">
                        <i class="fas fa-arrow-left mr-2"></i> Voltar
                    </button>
                    <div id="resultadoTipoVia" class="mt-2 text-center"></div>
                </div>

                <!-- Step 3: Dados pessoais -->
                <div class="step" id="step3">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Dados Pessoais</h2>

                    <div class="address-field">
                        <label for="nomeCompletoInput" class="block text-xs font-medium text-gray-700 mb-1">Nome Completo *</label>
                        <input type="text" id="nomeCompletoInput" placeholder="Digite seu nome completo" class="input-field" required>
                    </div>

                    <div class="address-field">
                        <label for="cpfInput" class="block text-xs font-medium text-gray-700 mb-1">CPF *</label>
                        <input type="text" id="cpfInput" placeholder="000.000.000-00" class="input-field" maxlength="14" required>
                    </div>

                    <div class="address-field">
                        <label for="nomeMaeInput" class="block text-xs font-medium text-gray-700 mb-1">Nome Completo da Mãe *</label>
                        <input type="text" id="nomeMaeInput" placeholder="Nome completo da mãe" class="input-field" required>
                        <p class="text-xs text-gray-500 mt-1">Seus dados são utilizados apenas para validação.</p>
                    </div>

                    <button onclick="validarDadosPessoais()" class="btn-primary">
                        <i class="fas fa-arrow-right mr-2"></i> Próximo
                    </button>
                    <button onclick="voltarStep(2)" class="btn-secondary">
                        <i class="fas fa-arrow-left mr-2"></i> Voltar
                    </button>
                    <div id="resultadoDadosPessoais" class="mt-2 text-center"></div>
                </div>

                <!-- Step 4: Confirmação dos dados -->
                <div class="step" id="step4">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Confirme seus Dados</h2>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Dados Pessoais</h3>
                        <div><strong>Nome Completo:</strong> <span id="nomeCompleto" class="font-medium"></span></div>
                        <div><strong>CPF:</strong> <span id="cpfExibir" class="font-medium"></span></div>
                        <div><strong>Nome da Mãe:</strong> <span id="nomeMaeCompleto" class="font-medium"></span></div>
                        <div><strong>Tipo de Via:</strong> <span id="viaSelecionada" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Localização</h3>
                        <div><strong>Estado Natal:</strong> <span id="estadoNatalExibir" class="font-medium"></span></div>
                        <div><strong>Cidade onde votará:</strong> <span id="cidadeVotoExibir" class="font-medium"></span></div>
                    </div>
                    <div class="btn-group">
                        <button onclick="proximoStep(5)" class="btn-primary">
                            <i class="fas fa-arrow-right mr-2"></i> Continuar
                        </button>
                        <button onclick="voltarStep(3)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                </div>

                <!-- Step 5: Endereço -->
                <div class="step" id="step5">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Informações de Endereço</h2>
                    <div class="address-field">
                        <label for="cepInput" class="block text-xs font-medium text-gray-700 mb-1">CEP *</label>
                        <input type="text" id="cepInput" placeholder="00000-000" class="input-field" maxlength="9">
                    </div>
                    <div class="address-field">
                        <label for="logradouro" class="block text-xs font-medium text-gray-700 mb-1">Logradouro *</label>
                        <input type="text" id="logradouro" class="input-field">
                    </div>
                    <div class="address-grid">
                        <div class="address-field">
                            <label for="numero" class="block text-xs font-medium text-gray-700 mb-1">Número *</label>
                            <input type="text" id="numero" class="input-field">
                        </div>
                        <div class="address-field">
                            <label for="complemento" class="block text-xs font-medium text-gray-700 mb-1">Complemento</label>
                            <input type="text" id="complemento" class="input-field" placeholder="Apto, Casa, etc.">
                        </div>
                    </div>
                    <div class="address-field">
                        <label for="bairro" class="block text-xs font-medium text-gray-900 mb-1">Bairro *</label>
                        <input type="text" id="bairro" class="input-field">
                    </div>
                    <div class="address-grid">
                        <div class="address-field">
                            <label for="cidade" class="block text-xs font-medium text-gray-700 mb-1">Cidade *</label>
                            <input type="text" id="cidade" class="input-field">
                        </div>
                        <div class="address-field">
                            <label for="uf" class="block text-xs font-medium text-gray-700 mb-1">Estado *</label>
                            <input type="text" id="uf" class="input-field" style="text-transform: uppercase;">
                        </div>
                    </div>
                    <div class="btn-group">
                        <button onclick="proximoStep(6)" class="btn-primary">
                            <i class="fas fa-arrow-right mr-2"></i> Prosseguir
                        </button>
                        <button onclick="voltarStep(4)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoEndereco" class="mt-2 text-center"></div>
                </div>

                <!-- Step 6: Confirmação Final -->
                <div class="step" id="step6">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Confirmação Final</h2>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Dados Pessoais</h3>
                        <div><strong>Nome Completo:</strong> <span id="nomeCompletoFinal" class="font-medium"></span></div>
                        <div><strong>CPF:</strong> <span id="cpfFinal" class="font-medium"></span></div>
                        <div><strong>Nome da Mãe:</strong> <span id="nomeMaeFinal" class="font-medium"></span></div>
                        <div><strong>Tipo de Via:</strong> <span id="viaSelecionadaFinal" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Localização</h3>
                        <div><strong>Estado Natal:</strong> <span id="estadoNatalFinal" class="font-medium"></span></div>
                        <div><strong>Cidade onde votará:</strong> <span id="cidadeVotoFinal" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Endereço</h3>
                        <div><strong>CEP:</strong> <span id="cepExibir" class="font-medium"></span></div>
                        <div><strong>Logradouro:</strong> <span id="logradouroFinal" class="font-medium"></span></div>
                        <div><strong>Número:</strong> <span id="numeroFinal" class="font-medium"></span></div>
                        <div><strong>Complemento:</strong> <span id="complementoFinal" class="font-medium"></span></div>
                        <div><strong>Bairro:</strong> <span id="bairroFinal" class="font-medium"></span></div>
                        <div><strong>Cidade:</strong> <span id="cidadeFinal" class="font-medium"></span></div>
                        <div><strong>Estado:</strong> <span id="ufFinal" class="font-medium"></span></div>
                    </div>
                    <div class="btn-group">
                        <button onclick="enviarSolicitacao()" class="btn-primary">
                            <i class="fas fa-check-circle mr-2"></i> Solicitar e-Doc
                        </button>
                        <button onclick="voltarStep(5)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoConfirmacao" class="mt-2 text-center"></div>
                </div>
            </div>
        </main>
    </div>

    <footer class="footer">
        <div class="copyright">
            <p>EdocBr © 2025 - Todos os direitos reservados</p>
            <p class="mt-1">
                <a href="/termos">Termos de Uso</a> | 
                <a href="/privacidade">Política de Privacidade</a>
            </p>
        </div>
    </footer>

    <script>
        let dadosFormulario = {
            estadoNatal: '',
            cidadeVoto: '',
            tipoVia: '',
            nomeCompleto: '',
            cpf: '',
            nomeMae: '',
            cep: '',
            logradouro: '',
            numero: '',
            complemento: '',
            bairro: '',
            cidade: '',
            uf: ''
        };

        // Mobile Menu Toggle
        const mobileMenuBtn = document.getElementById('mobileMenuBtn');
        const navMenu = document.getElementById('navMenu');

        mobileMenuBtn.addEventListener('click', () => {
            navMenu.classList.toggle('active');
            mobileMenuBtn.innerHTML = navMenu.classList.contains('active') 
                ? '<i class="fas fa-times"></i>' 
                : '<i class="fas fa-bars"></i>';
        });

        // Máscara de CPF
        document.getElementById('cpfInput').addEventListener('input', function (e) {
            let value = e.target.value.replace(/\D/g, '');
            if (value.length > 11) value = value.slice(0, 11);
            value = value.replace(/^(\d{3})(\d)/, '$1.$2')
                        .replace(/^(\d{3})\.(\d{3})(\d)/, '$1.$2.$3')
                        .replace(/\.(\d{3})(\d)/, '.$1-$2');
            e.target.value = value;
        });

        // Máscara de CEP e busca automática
        document.getElementById('cepInput').addEventListener('input', function (e) {
            let value = e.target.value.replace(/\D/g, '');
            if (value.length > 8) value = value.slice(0, 8);
            value = value.replace(/^(\d{5})(\d)/, '$1-$2');
            e.target.value = value;

            if (value.replace(/\D/g, '').length === 8) {
                buscarCEP();
            } else {
                limparCamposEndereco();
            }
        });

        // Validação de CPF
        function validarCPF(cpf) {
            cpf = cpf.replace(/[^\d]/g, '');
            if (cpf.length !== 11) return false;
            if (/^(\d)\1{10}$/.test(cpf)) return false;
            let soma = 0;
            for (let i = 0; i < 9; i++) soma += parseInt(cpf.charAt(i)) * (10 - i);
            let resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            if (resto !== parseInt(cpf.charAt(9))) return false;
            soma = 0;
            for (let i = 0; i < 10; i++) soma += parseInt(cpf.charAt(i)) * (11 - i);
            resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            return resto === parseInt(cpf.charAt(10));
        }

        // Exibir mensagens de feedback
        function showMessage(elementId, type, message) {
            const resultadoDiv = document.getElementById(elementId);
            resultadoDiv.innerHTML = `<p class="${type}">${message}</p>`;
            setTimeout(() => resultadoDiv.innerHTML = '', 3000);
        }

        // Step 1: Validar informações iniciais
        function validarInformacoesIniciais() {
            const estadoNatal = document.getElementById('estadoNatalInput').value;
            const cidadeVoto = document.getElementById('cidadeVotoInput').value.trim();

            if (!estadoNatal) {
                showMessage('resultadoInicial', 'error', 'Por favor, selecione o estado natal');
                return;
            }

            if (!cidadeVoto || cidadeVoto.length < 3) {
                showMessage('resultadoInicial', 'error', 'Por favor, informe a cidade onde votará');
                return;
            }

            dadosFormulario.estadoNatal = estadoNatal;
            dadosFormulario.cidadeVoto = cidadeVoto;

            proximoStep(2);
        }

        // Step 2: Validar tipo de via e aceite
        function validarTipoVia() {
            const viaSelecionada = document.querySelector('input[name="via"]:checked');
            const aceitoTermos = document.getElementById('aceitoTermos').checked;

            if (!viaSelecionada) {
                showMessage('resultadoTipoVia', 'error', 'Por favor, selecione o tipo de via');
                return;
            }

            if (!aceitoTermos) {
                showMessage('resultadoTipoVia', 'error', 'Você precisa aceitar os termos para continuar');
                return;
            }

            dadosFormulario.tipoVia = viaSelecionada.value;
            proximoStep(3);
        }

        // Step 3: Validar dados pessoais
        function validarDadosPessoais() {
            const nomeCompleto = document.getElementById('nomeCompletoInput').value.trim();
            const cpf = document.getElementById('cpfInput').value;
            const nomeMae = document.getElementById('nomeMaeInput').value.trim();

            if (!nomeCompleto || nomeCompleto.length < 3) {
                showMessage('resultadoDadosPessoais', 'error', 'Por favor, informe seu nome completo');
                return;
            }

            if (!cpf) {
                showMessage('resultadoDadosPessoais', 'error', 'Por favor, informe seu CPF');
                return;
            }

            const cpfPattern = /^\d{3}\.\d{3}\.\d{3}-\d{2}$/;
            if (!cpfPattern.test(cpf)) {
                showMessage('resultadoDadosPessoais', 'error', 'Formato de CPF inválido. Use: 000.000.000-00');
                return;
            }

            if (!validarCPF(cpf)) {
                showMessage('resultadoDadosPessoais', 'error', 'CPF inválido. Verifique os dígitos.');
                return;
            }

            if (!nomeMae || nomeMae.length < 3) {
                showMessage('resultadoDadosPessoais', 'error', 'Por favor, informe o nome completo da mãe');
                return;
            }

            dadosFormulario.nomeCompleto = nomeCompleto;
            dadosFormulario.cpf = cpf;
            dadosFormulario.nomeMae = nomeMae;

            // Preencher preview do Step 4
            document.getElementById('nomeCompleto').textContent = nomeCompleto.toUpperCase();
            document.getElementById('cpfExibir').textContent = cpf;
            document.getElementById('nomeMaeCompleto').textContent = nomeMae.toUpperCase();
            document.getElementById('viaSelecionada').textContent = dadosFormulario.tipoVia;

            const estadoNome = document.getElementById('estadoNatalInput').selectedOptions[0].text;
            document.getElementById('estadoNatalExibir').textContent = estadoNome;
            document.getElementById('cidadeVotoExibir').textContent = dadosFormulario.cidadeVoto.toUpperCase();

            proximoStep(4);
        }

        // Navegação entre steps
        function proximoStep(step) {
            // Validações específicas antes de avançar para step 6
            if (step === 6) {
                const cep = document.getElementById('cepInput').value;
                const logradouro = document.getElementById('logradouro').value.trim();
                const numero = document.getElementById('numero').value.trim();
                const bairro = document.getElementById('bairro').value.trim();
                const cidade = document.getElementById('cidade').value.trim();
                const uf = document.getElementById('uf').value.trim();

                if (!cep || cep.replace(/\D/g, '').length !== 8) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe um CEP válido');
                    return;
                }

                if (!logradouro) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe o logradouro');
                    return;
                }

                if (!numero) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe o número');
                    return;
                }

                if (!bairro) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe o bairro');
                    return;
                }

                if (!cidade) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe a cidade');
                    return;
                }

                if (!uf) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe o estado');
                    return;
                }

                // Salvar dados de endereço
                dadosFormulario.cep = cep;
                dadosFormulario.logradouro = logradouro;
                dadosFormulario.numero = numero;
                dadosFormulario.complemento = document.getElementById('complemento').value.trim();
                dadosFormulario.bairro = bairro;
                dadosFormulario.cidade = cidade;
                dadosFormulario.uf = uf;

                // Preencher confirmação final
                document.getElementById('nomeCompletoFinal').textContent = dadosFormulario.nomeCompleto.toUpperCase();
                document.getElementById('cpfFinal').textContent = dadosFormulario.cpf;
                document.getElementById('nomeMaeFinal').textContent = dadosFormulario.nomeMae.toUpperCase();
                document.getElementById('viaSelecionadaFinal').textContent = dadosFormulario.tipoVia;

                const estadoNome = document.getElementById('estadoNatalInput').selectedOptions[0].text;
                document.getElementById('estadoNatalFinal').textContent = estadoNome;
                document.getElementById('cidadeVotoFinal').textContent = dadosFormulario.cidadeVoto.toUpperCase();

                document.getElementById('cepExibir').textContent = dadosFormulario.cep;
                document.getElementById('logradouroFinal').textContent = dadosFormulario.logradouro;
                document.getElementById('numeroFinal').textContent = dadosFormulario.numero;
                document.getElementById('complementoFinal').textContent = dadosFormulario.complemento || 'Não informado';
                document.getElementById('bairroFinal').textContent = dadosFormulario.bairro;
                document.getElementById('cidadeFinal').textContent = dadosFormulario.cidade;
                document.getElementById('ufFinal').textContent = dadosFormulario.uf;
            }

            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        function voltarStep(step) {
            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        // Buscar CEP nas APIs
        async function buscarCEP() {
            const cepInput = document.getElementById('cepInput').value;
            const resultadoDiv = document.getElementById('resultadoEndereco');
            const cep = cepInput.replace(/\D/g, '');

            if (cep.length !== 8) {
                return;
            }

            resultadoDiv.innerHTML = '<p class="success">Buscando CEP...</p>';

            try {
                // Tentar BrasilAPI primeiro
                const response = await fetch(`https://brasilapi.com.br/api/cep/v1/${cep}`);

                if (!response.ok) {
                    throw new Error('CEP não encontrado na BrasilAPI');
                }

                const data = await response.json();

                document.getElementById('logradouro').value = data.street || '';
                document.getElementById('bairro').value = data.neighborhood || '';
                document.getElementById('cidade').value = data.city || '';
                document.getElementById('uf').value = data.state || '';

                resultadoDiv.innerHTML = '';
                showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

            } catch (error) {
                try {
                    // Tentar ViaCEP como alternativa
                    const response2 = await fetch(`https://viacep.com.br/ws/${cep}/json/`);
                    const data2 = await response2.json();

                    if (data2.erro === true) {
                        throw new Error('CEP não encontrado');
                    }

                    document.getElementById('logradouro').value = data2.logradouro || '';
                    document.getElementById('bairro').value = data2.bairro || '';
                    document.getElementById('cidade').value = data2.localidade || '';
                    document.getElementById('uf').value = data2.uf || '';
                    if (data2.complemento) {
                        document.getElementById('complemento').value = data2.complemento;
                    }

                    resultadoDiv.innerHTML = '';
                    showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

                } catch (error2) {
                    console.error('Erro ao buscar CEP:', error2);
                    showMessage('resultadoEndereco', 'error', 'CEP não encontrado. Verifique e tente novamente.');
                    limparCamposEndereco();
                }
            }
        }

        function limparCamposEndereco() {
            document.getElementById('logradouro').value = '';
            document.getElementById('bairro').value = '';
            document.getElementById('cidade').value = '';
            document.getElementById('uf').value = '';
        }

        // Redirecionando ao pagamento
        function enviarSolicitacao() {
            const resultadoDiv = document.getElementById('resultadoConfirmacao');

            resultadoDiv.innerHTML = '<p class="success">Processando solicitação... Redirecionando para o pagamento...</p>';

            const checkoutUrl = `https://pay.docfacil.digital/v7R0glkabeVGVr9`;

            setTimeout(() => {
                window.location.href = checkoutUrl;
            }, 1000);
        }
    </script>
</body>
</html>"},"elements":[],"widgetType":"html"}],"isInner":false}]

{"timeout":1771533133,"value":{"content":"<div class="elementor-element elementor-element-2c0fb9bc e-flex e-con-boxed e-con e-parent" data-id="2c0fb9bc" data-element_type="container">
					<div class="e-con-inner">
				<div class="elementor-element elementor-element-5f9d96ce elementor-widget elementor-widget-html" data-id="5f9d96ce" data-element_type="widget" data-widget_type="html.default">
					<!DOCTYPE html>
<html lang="pt-BR">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>EdocBr | Solicitação de e-Doc</title>
    <meta name="description" content="Auxílio do EdocBr de forma prática e segura.">
    <script src="https://cdn.tailwindcss.com"></script>
    <script src="https://code.jquery.com/jquery-3.6.0.min.js"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap" rel="stylesheet">
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0/css/all.min.css">
    <style>
        :root {
            --primary-color: #027d6c;
            --secondary-color: #10b981;
            --light-color: #ecfdf5;
            --dark-color: #064e3b;
            --text-color: #1f2937;
            --accent-color: #34d399;
        }
        * {
            box-sizing: border-box;
        }
        body {
            font-family: 'Inter', sans-serif;
            background: linear-gradient(180deg, #f3f4f6 0%, #e5e7eb 100%);
            color: var(--text-color);
            line-height: 1.6;
            margin: 0;
            padding: 0;
            min-height: 100vh;
            display: flex;
            flex-direction: column;
        }
        .main-wrapper {
            flex: 1;
            max-width: 1280px;
            margin: 0 auto;
            width: 100%;
            padding: 0 0.5rem;
        }
        .header {
            background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
            color: white;
            padding: 0.75rem;
            display: flex;
            align-items: center;
            justify-content: space-between;
            position: sticky;
            top: 0;
            z-index: 100;
            box-shadow: 0 3px 10px rgba(0, 0, 0, 0.1);
            border-bottom-left-radius: 10px;
            border-bottom-right-radius: 10px;
        }
        .logo-container {
            display: flex;
            align-items: center;
            gap: 0.5rem;
        }
        .logo {
            width: 32px;
            height: 32px;
            object-fit: contain;
            transition: transform 0.3s ease;
        }
        .logo:hover {
            transform: scale(1.1);
        }
        .brand-name {
            font-weight: 800;
            font-size: 1.1rem;
            letter-spacing: -0.025em;
        }
        .mobile-menu-btn {
            background: none;
            border: none;
            color: white;
            font-size: 1.25rem;
            cursor: pointer;
            transition: transform 0.3s ease;
        }
        .mobile-menu-btn:hover {
            transform: rotate(90deg);
        }
        .nav-menu {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: linear-gradient(135deg, var(--primary-color), var(--dark-color));
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            transform: translateY(-100%);
            transition: transform 0.3s ease;
            z-index: 99;
            padding: 0.75rem;
        }
        .nav-menu.active {
            transform: translateY(0);
        }
        .nav-menu ul {
            list-style: none;
            padding: 0;
            margin: 0;
            display: flex;
            flex-direction: column;
            gap: 1rem;
            width: 100%;
            text-align: center;
        }
        .nav-menu ul li a {
            color: white;
            text-decoration: none;
            font-size: 1rem;
            font-weight: 600;
            padding: 0.5rem;
            display: block;
            transition: all 0.3s ease;
        }
        .nav-menu ul li a:hover {
            color: var(--light-color);
            background: rgba(255, 255, 255, 0.1);
            border-radius: 6px;
        }
        .main-content {
            padding: 1.5rem 0.25rem;
        }
        .container {
            background: white;
            border-radius: 8px;
            box-shadow: 0 4px 16px rgba(0, 0, 0, 0.06);
            padding: 1rem;
            width: 95%;
            margin: 0 auto;
            transition: transform 0.3s ease;
        }
        .container:hover {
            transform: translateY(-3px);
        }
        .section-title {
            font-size: 1.4rem;
            font-weight: 800;
            text-align: center;
            color: var(--primary-color);
            margin-bottom: 1rem;
            position: relative;
        }
        .section-title::after {
            content: '';
            position: absolute;
            bottom: -0.4rem;
            left: 50%;
            transform: translateX(-50%);
            width: 60px;
            height: 3px;
            background: linear-gradient(to right, var(--primary-color), var(--accent-color));
            border-radius: 2px;
        }
        .btn-primary {
            background: var(--primary-color);
            color: white;
            padding: 0.875rem 1.75rem;
            border-radius: 6px;
            font-weight: 600;
            font-size: 0.9rem;
            text-align: center;
            display: block;
            text-decoration: none;
            border: none;
            cursor: pointer;
            transition: all 0.3s ease;
            width: 100%;
            margin: 0.5rem 0;
            box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);
        }
        .btn-primary:hover:not(:disabled) {
            background: var(--dark-color);
            transform: translateY(-2px);
            box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
        }
        .btn-primary:disabled {
            background: #d1d5db;
            cursor: not-allowed;
        }
        .btn-secondary {
            background: #6b7280;
            color: white;
            padding: 0.75rem 1.5rem;
            border-radius: 6px;
            font-weight: 600;
            font-size: 0.9rem;
            text-align: center;
            display: block;
            text-decoration: none;
            border: none;
            cursor: pointer;
            transition: all 0.3s ease;
            width: 100%;
            margin: 0.5rem 0;
            box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);
        }
        .btn-secondary:hover {
            background: #4b5563;
            transform: translateY(-2px);
            box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
        }
        .input-field, .select-field {
            width: 100%;
            padding: 0.6rem;
            border: 1px solid #d1d5db;
            border-radius: 6px;
            font-size: 16px;
            margin-bottom: 0.5rem;
            transition: all 0.3s ease;
            background: #f9fafb;
            box-sizing: border-box;
        }
        .input-field:focus, .select-field:focus {
            outline: none;
            border-color: var(--primary-color);
            box-shadow: 0 0 0 2px rgba(2, 125, 108, 0.15);
        }
        .input-field:disabled {
            background: #f3f4f6;
            color: #6b7280;
        }
        .radio-field {
            display: flex;
            align-items: center;
            margin-bottom: 0.4rem;
            gap: 0.4rem;
        }
        .radio-field input[type="radio"] {
            accent-color: var(--primary-color);
            width: 1rem;
            height: 1rem;
        }
        .radio-field label {
            font-size: 0.9rem;
            color: var(--text-color);
        }
        .preview-box {
            border: 1px solid #e5e7eb;
            border-radius: 6px;
            padding: 1rem;
            background: #f9fafb;
            margin-bottom: 0.75rem;
            transition: all 0.3s ease;
        }
        .preview-box:hover {
            border-color: var(--accent-color);
        }
        .preview-box div {
            margin-bottom: 0.4rem;
            color: var(--text-color);
            font-size: 0.9rem;
        }
        .error {
            color: #dc2626;
            font-weight: 600;
            font-size: 0.8rem;
        }
        .success {
            color: var(--primary-color);
            font-weight: 600;
            font-size: 0.8rem;
        }
        .step {
            display: none;
        }
        .step.active {
            display: block;
            animation: fadeIn 0.5s ease-in;
        }
        @keyframes fadeIn {
            from { opacity: 0; transform: translateY(10px); }
            to { opacity: 1; transform: translateY(0); }
        }
        .footer {
            background: linear-gradient(135deg, var(--primary-color), var(--dark-color));
            color: white;
            padding: 1.5rem 0.75rem;
            text-align: center;
            width: 100%;
            border-top-left-radius: 10px;
            border-top-right-radius: 10px;
        }
        .footer a {
            color: var(--light-color);
            text-decoration: underline;
            transition: color 0.3s ease;
        }
        .footer a:hover {
            color: white;
        }
        .copyright {
            margin-top: 0.75rem;
            font-size: 0.8rem;
            color: #d1fae5;
        }
        .address-field {
            margin-bottom: 0.5rem;
        }
        .address-field label {
            display: block;
            margin-bottom: 0.4rem;
            font-weight: 600;
            color: var(--text-color);
            font-size: 0.9rem;
        }
        .address-grid {
            display: grid;
            gap: 0.5rem;
        }
        .btn-group {
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
            justify-content: center;
        }
        .info-message {
            background: var(--light-color);
            border-left: 4px solid var(--primary-color);
            padding: 1rem;
            border-radius: 6px;
            margin: 1rem 0;
        }
        .info-message p {
            margin: 0.3rem 0;
            color: var(--dark-color);
            font-weight: 500;
            font-size: 0.9rem;
            line-height: 1.5;
        }
        .checkbox-field {
            display: flex;
            align-items: flex-start;
            margin: 1rem 0;
            gap: 0.6rem;
        }
        .checkbox-field input[type="checkbox"] {
            accent-color: var(--primary-color);
            width: 1.2rem;
            height: 1.2rem;
            margin-top: 0.1rem;
            flex-shrink: 0;
        }
        .checkbox-field label {
            font-size: 0.85rem;
            color: var(--text-color);
            line-height: 1.5;
        }
        @media (min-width: 768px) {
            .header {
                padding: 1rem 1.5rem;
            }
            .mobile-menu-btn {
                display: none;
            }
            .nav-menu {
                position: static;
                background: transparent;
                transform: none;
                flex-direction: row;
                justify-content: flex-end;
                padding: 0;
            }
            .nav-menu ul {
                flex-direction: row;
                gap: 1.5rem;
                width: auto;
            }
            .nav-menu ul li a {
                font-size: 0.9rem;
            }
            .main-content {
                padding: 2.5rem 1rem;
            }
            .container {
                padding: 2rem;
                border-radius: 12px;
                max-width: 720px;
            }
            .section-title {
                font-size: 1.8rem;
            }
            .btn-primary {
                padding: 0.875rem 2rem;
                font-size: 1rem;
            }
            .btn-secondary {
                padding: 0.875rem 2rem;
                font-size: 1rem;
            }
            .btn-group {
                flex-direction: row;
                gap: 1rem;
            }
            .btn-group .btn-primary, .btn-group .btn-secondary {
                width: auto;
                flex: 1;
                max-width: 180px;
            }
            .address-grid {
                grid-template-columns: 1fr 2fr;
            }
            .input-field, .select-field {
                padding: 0.75rem;
                font-size: 16px;
            }
            .preview-box {
                padding: 1.25rem;
                font-size: 0.95rem;
            }
            .preview-box div {
                font-size: 0.95rem;
            }
        }
    </style>
</head>
<body>
    <div class="main-wrapper">
        <header class="header">
            <div class="logo-container">
                <img src="https://cdn-icons-png.flaticon.com/512/197/197386.png" alt="EdocBr Logo" class="logo">
                <span class="brand-name">Título EdocBr</span>
            </div>
            <button class="mobile-menu-btn" id="mobileMenuBtn">
                <i class="fas fa-bars"></i>
            </button>
            <nav class="nav-menu" id="navMenu">
                <ul>
                    <li><a href="/">Voltar ao Início</a></li>
                </ul>
            </nav>
        </header>

        <main class="main-content">
            <div class="container">
                <h1 class="section-title">Solicitação de e-Doc Tipo: Regularizar Título</h1>

                <!-- Step 1: Estado Natal e Cidade onde exercerá o voto -->
                <div class="step active" id="step1">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Informações Iniciais</h2>
                    <div class="address-field">
                        <label for="estadoNatalInput" class="block text-xs font-medium text-gray-700 mb-1">Estado Natal *</label>
                        <select id="estadoNatalInput" class="select-field" required>
                            <option value="">Selecione o estado</option>
                            <option value="AC">Acre (AC)</option>
                            <option value="AL">Alagoas (AL)</option>
                            <option value="AP">Amapá (AP)</option>
                            <option value="AM">Amazonas (AM)</option>
                            <option value="BA">Bahia (BA)</option>
                            <option value="CE">Ceará (CE)</option>
                            <option value="DF">Distrito Federal (DF)</option>
                            <option value="ES">Espírito Santo (ES)</option>
                            <option value="GO">Goiás (GO)</option>
                            <option value="MA">Maranhão (MA)</option>
                            <option value="MT">Mato Grosso (MT)</option>
                            <option value="MS">Mato Grosso do Sul (MS)</option>
                            <option value="MG">Minas Gerais (MG)</option>
                            <option value="PA">Pará (PA)</option>
                            <option value="PB">Paraíba (PB)</option>
                            <option value="PR">Paraná (PR)</option>
                            <option value="PE">Pernambuco (PE)</option>
                            <option value="PI">Piauí (PI)</option>
                            <option value="RJ">Rio de Janeiro (RJ)</option>
                            <option value="RN">Rio Grande do Norte (RN)</option>
                            <option value="RS">Rio Grande do Sul (RS)</option>
                            <option value="RO">Rondônia (RO)</option>
                            <option value="RR">Roraima (RR)</option>
                            <option value="SC">Santa Catarina (SC)</option>
                            <option value="SP">São Paulo (SP)</option>
                            <option value="SE">Sergipe (SE)</option>
                            <option value="TO">Tocantins (TO)</option>
                        </select>
                    </div>
                    <div class="address-field">
                        <label for="cidadeVotoInput" class="block text-xs font-medium text-gray-700 mb-1">Cidade onde exercerá o voto *</label>
                        <input type="text" id="cidadeVotoInput" placeholder="Digite a cidade" class="input-field" required>
                        <p class="text-xs text-gray-500 mt-1">Informe a cidade onde deseja exercer seu direito ao voto.</p>
                    </div>
                    <button onclick="validarInformacoesIniciais()" class="btn-primary">
                        <i class="fas fa-arrow-right mr-2"></i> Próximo
                    </button>
                    <div id="resultadoInicial" class="mt-2 text-center"></div>
                </div>

                <!-- Step 2: Tipo de via e aceite de termos -->
                <div class="step" id="step2">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Tipo de Documento</h2>
                    <div class="address-field">
                        <label class="block text-xs font-medium text-gray-700 mb-1">Selecione o tipo de via *</label>
                        <div class="radio-field">
                            <input type="radio" name="via" value="Primeira Via" id="via1" required>
                            <label for="via1">Primeira Via</label>
                        </div>
                        <div class="radio-field">
                            <input type="radio" name="via" value="Segunda Via" id="via2">
                            <label for="via2">Segunda Via</label>
                        </div>
                    </div>

                    <div class="info-message">
                        <p><strong>Segurança dos seus dados</strong></p>
                        <p>Para continuar a análise, precisamos validar seus dados. O CPF é usado exclusivamente para consulta e não é armazenado.</p>
                    </div>

                    <div class="checkbox-field">
                        <input type="checkbox" id="aceitoTermos" required>
                        <label for="aceitoTermos">Li e aceito os termos de uso. Entendo que meus dados serão utilizados apenas para validação e não serão armazenados.</label>
                    </div>

                    <button onclick="validarTipoVia()" class="btn-primary">
                        <i class="fas fa-check mr-2"></i> Entendi e aceito
                    </button>
                    <button onclick="voltarStep(1)" class="btn-secondary">
                        <i class="fas fa-arrow-left mr-2"></i> Voltar
                    </button>
                    <div id="resultadoTipoVia" class="mt-2 text-center"></div>
                </div>

                <!-- Step 3: Dados pessoais -->
                <div class="step" id="step3">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Dados Pessoais</h2>

                    <div class="address-field">
                        <label for="nomeCompletoInput" class="block text-xs font-medium text-gray-700 mb-1">Nome Completo *</label>
                        <input type="text" id="nomeCompletoInput" placeholder="Digite seu nome completo" class="input-field" required>
                    </div>

                    <div class="address-field">
                        <label for="cpfInput" class="block text-xs font-medium text-gray-700 mb-1">CPF *</label>
                        <input type="text" id="cpfInput" placeholder="000.000.000-00" class="input-field" maxlength="14" required>
                    </div>

                    <div class="address-field">
                        <label for="nomeMaeInput" class="block text-xs font-medium text-gray-700 mb-1">Nome Completo da Mãe *</label>
                        <input type="text" id="nomeMaeInput" placeholder="Nome completo da mãe" class="input-field" required>
                        <p class="text-xs text-gray-500 mt-1">Seus dados são utilizados apenas para validação.</p>
                    </div>

                    <button onclick="validarDadosPessoais()" class="btn-primary">
                        <i class="fas fa-arrow-right mr-2"></i> Próximo
                    </button>
                    <button onclick="voltarStep(2)" class="btn-secondary">
                        <i class="fas fa-arrow-left mr-2"></i> Voltar
                    </button>
                    <div id="resultadoDadosPessoais" class="mt-2 text-center"></div>
                </div>

                <!-- Step 4: Confirmação dos dados -->
                <div class="step" id="step4">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Confirme seus Dados</h2>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Dados Pessoais</h3>
                        <div><strong>Nome Completo:</strong> <span id="nomeCompleto" class="font-medium"></span></div>
                        <div><strong>CPF:</strong> <span id="cpfExibir" class="font-medium"></span></div>
                        <div><strong>Nome da Mãe:</strong> <span id="nomeMaeCompleto" class="font-medium"></span></div>
                        <div><strong>Tipo de Via:</strong> <span id="viaSelecionada" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Localização</h3>
                        <div><strong>Estado Natal:</strong> <span id="estadoNatalExibir" class="font-medium"></span></div>
                        <div><strong>Cidade onde votará:</strong> <span id="cidadeVotoExibir" class="font-medium"></span></div>
                    </div>
                    <div class="btn-group">
                        <button onclick="proximoStep(5)" class="btn-primary">
                            <i class="fas fa-arrow-right mr-2"></i> Continuar
                        </button>
                        <button onclick="voltarStep(3)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                </div>

                <!-- Step 5: Endereço -->
                <div class="step" id="step5">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Informações de Endereço</h2>
                    <div class="address-field">
                        <label for="cepInput" class="block text-xs font-medium text-gray-700 mb-1">CEP *</label>
                        <input type="text" id="cepInput" placeholder="00000-000" class="input-field" maxlength="9">
                    </div>
                    <div class="address-field">
                        <label for="logradouro" class="block text-xs font-medium text-gray-700 mb-1">Logradouro *</label>
                        <input type="text" id="logradouro" class="input-field">
                    </div>
                    <div class="address-grid">
                        <div class="address-field">
                            <label for="numero" class="block text-xs font-medium text-gray-700 mb-1">Número *</label>
                            <input type="text" id="numero" class="input-field">
                        </div>
                        <div class="address-field">
                            <label for="complemento" class="block text-xs font-medium text-gray-700 mb-1">Complemento</label>
                            <input type="text" id="complemento" class="input-field" placeholder="Apto, Casa, etc.">
                        </div>
                    </div>
                    <div class="address-field">
                        <label for="bairro" class="block text-xs font-medium text-gray-900 mb-1">Bairro *</label>
                        <input type="text" id="bairro" class="input-field">
                    </div>
                    <div class="address-grid">
                        <div class="address-field">
                            <label for="cidade" class="block text-xs font-medium text-gray-700 mb-1">Cidade *</label>
                            <input type="text" id="cidade" class="input-field">
                        </div>
                        <div class="address-field">
                            <label for="uf" class="block text-xs font-medium text-gray-700 mb-1">Estado *</label>
                            <input type="text" id="uf" class="input-field" style="text-transform: uppercase;">
                        </div>
                    </div>
                    <div class="btn-group">
                        <button onclick="proximoStep(6)" class="btn-primary">
                            <i class="fas fa-arrow-right mr-2"></i> Prosseguir
                        </button>
                        <button onclick="voltarStep(4)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoEndereco" class="mt-2 text-center"></div>
                </div>

                <!-- Step 6: Confirmação Final -->
                <div class="step" id="step6">
                    <h2 class="text-lg font-semibold mb-3 text-center text-gray-800">Confirmação Final</h2>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Dados Pessoais</h3>
                        <div><strong>Nome Completo:</strong> <span id="nomeCompletoFinal" class="font-medium"></span></div>
                        <div><strong>CPF:</strong> <span id="cpfFinal" class="font-medium"></span></div>
                        <div><strong>Nome da Mãe:</strong> <span id="nomeMaeFinal" class="font-medium"></span></div>
                        <div><strong>Tipo de Via:</strong> <span id="viaSelecionadaFinal" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Localização</h3>
                        <div><strong>Estado Natal:</strong> <span id="estadoNatalFinal" class="font-medium"></span></div>
                        <div><strong>Cidade onde votará:</strong> <span id="cidadeVotoFinal" class="font-medium"></span></div>
                    </div>
                    <div class="preview-box">
                        <h3 class="text-sm font-semibold mb-2 text-gray-800">Endereço</h3>
                        <div><strong>CEP:</strong> <span id="cepExibir" class="font-medium"></span></div>
                        <div><strong>Logradouro:</strong> <span id="logradouroFinal" class="font-medium"></span></div>
                        <div><strong>Número:</strong> <span id="numeroFinal" class="font-medium"></span></div>
                        <div><strong>Complemento:</strong> <span id="complementoFinal" class="font-medium"></span></div>
                        <div><strong>Bairro:</strong> <span id="bairroFinal" class="font-medium"></span></div>
                        <div><strong>Cidade:</strong> <span id="cidadeFinal" class="font-medium"></span></div>
                        <div><strong>Estado:</strong> <span id="ufFinal" class="font-medium"></span></div>
                    </div>
                    <div class="btn-group">
                        <button onclick="enviarSolicitacao()" class="btn-primary">
                            <i class="fas fa-check-circle mr-2"></i> Solicitar e-Doc
                        </button>
                        <button onclick="voltarStep(5)" class="btn-secondary">
                            <i class="fas fa-arrow-left mr-2"></i> Voltar
                        </button>
                    </div>
                    <div id="resultadoConfirmacao" class="mt-2 text-center"></div>
                </div>
            </div>
        </main>
    </div>

    <footer class="footer">
        <div class="copyright">
            <p>EdocBr © 2025 - Todos os direitos reservados</p>
            <p class="mt-1">
                <a href="/termos">Termos de Uso</a> | 
                <a href="/privacidade">Política de Privacidade</a>
            </p>
        </div>
    </footer>

    <script>
        let dadosFormulario = {
            estadoNatal: '',
            cidadeVoto: '',
            tipoVia: '',
            nomeCompleto: '',
            cpf: '',
            nomeMae: '',
            cep: '',
            logradouro: '',
            numero: '',
            complemento: '',
            bairro: '',
            cidade: '',
            uf: ''
        };

        // Mobile Menu Toggle
        const mobileMenuBtn = document.getElementById('mobileMenuBtn');
        const navMenu = document.getElementById('navMenu');

        mobileMenuBtn.addEventListener('click', () => {
            navMenu.classList.toggle('active');
            mobileMenuBtn.innerHTML = navMenu.classList.contains('active') 
                ? '<i class="fas fa-times"></i>' 
                : '<i class="fas fa-bars"></i>';
        });

        // Máscara de CPF
        document.getElementById('cpfInput').addEventListener('input', function (e) {
            let value = e.target.value.replace(/\D/g, '');
            if (value.length > 11) value = value.slice(0, 11);
            value = value.replace(/^(\d{3})(\d)/, '$1.$2')
                        .replace(/^(\d{3})\.(\d{3})(\d)/, '$1.$2.$3')
                        .replace(/\.(\d{3})(\d)/, '.$1-$2');
            e.target.value = value;
        });

        // Máscara de CEP e busca automática
        document.getElementById('cepInput').addEventListener('input', function (e) {
            let value = e.target.value.replace(/\D/g, '');
            if (value.length > 8) value = value.slice(0, 8);
            value = value.replace(/^(\d{5})(\d)/, '$1-$2');
            e.target.value = value;

            if (value.replace(/\D/g, '').length === 8) {
                buscarCEP();
            } else {
                limparCamposEndereco();
            }
        });

        // Validação de CPF
        function validarCPF(cpf) {
            cpf = cpf.replace(/[^\d]/g, '');
            if (cpf.length !== 11) return false;
            if (/^(\d)\1{10}$/.test(cpf)) return false;
            let soma = 0;
            for (let i = 0; i < 9; i++) soma += parseInt(cpf.charAt(i)) * (10 - i);
            let resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            if (resto !== parseInt(cpf.charAt(9))) return false;
            soma = 0;
            for (let i = 0; i < 10; i++) soma += parseInt(cpf.charAt(i)) * (11 - i);
            resto = (soma * 10) % 11;
            if (resto === 10 || resto === 11) resto = 0;
            return resto === parseInt(cpf.charAt(10));
        }

        // Exibir mensagens de feedback
        function showMessage(elementId, type, message) {
            const resultadoDiv = document.getElementById(elementId);
            resultadoDiv.innerHTML = `<p class="${type}">${message}</p>`;
            setTimeout(() => resultadoDiv.innerHTML = '', 3000);
        }

        // Step 1: Validar informações iniciais
        function validarInformacoesIniciais() {
            const estadoNatal = document.getElementById('estadoNatalInput').value;
            const cidadeVoto = document.getElementById('cidadeVotoInput').value.trim();

            if (!estadoNatal) {
                showMessage('resultadoInicial', 'error', 'Por favor, selecione o estado natal');
                return;
            }

            if (!cidadeVoto || cidadeVoto.length < 3) {
                showMessage('resultadoInicial', 'error', 'Por favor, informe a cidade onde votará');
                return;
            }

            dadosFormulario.estadoNatal = estadoNatal;
            dadosFormulario.cidadeVoto = cidadeVoto;

            proximoStep(2);
        }

        // Step 2: Validar tipo de via e aceite
        function validarTipoVia() {
            const viaSelecionada = document.querySelector('input[name="via"]:checked');
            const aceitoTermos = document.getElementById('aceitoTermos').checked;

            if (!viaSelecionada) {
                showMessage('resultadoTipoVia', 'error', 'Por favor, selecione o tipo de via');
                return;
            }

            if (!aceitoTermos) {
                showMessage('resultadoTipoVia', 'error', 'Você precisa aceitar os termos para continuar');
                return;
            }

            dadosFormulario.tipoVia = viaSelecionada.value;
            proximoStep(3);
        }

        // Step 3: Validar dados pessoais
        function validarDadosPessoais() {
            const nomeCompleto = document.getElementById('nomeCompletoInput').value.trim();
            const cpf = document.getElementById('cpfInput').value;
            const nomeMae = document.getElementById('nomeMaeInput').value.trim();

            if (!nomeCompleto || nomeCompleto.length < 3) {
                showMessage('resultadoDadosPessoais', 'error', 'Por favor, informe seu nome completo');
                return;
            }

            if (!cpf) {
                showMessage('resultadoDadosPessoais', 'error', 'Por favor, informe seu CPF');
                return;
            }

            const cpfPattern = /^\d{3}\.\d{3}\.\d{3}-\d{2}$/;
            if (!cpfPattern.test(cpf)) {
                showMessage('resultadoDadosPessoais', 'error', 'Formato de CPF inválido. Use: 000.000.000-00');
                return;
            }

            if (!validarCPF(cpf)) {
                showMessage('resultadoDadosPessoais', 'error', 'CPF inválido. Verifique os dígitos.');
                return;
            }

            if (!nomeMae || nomeMae.length < 3) {
                showMessage('resultadoDadosPessoais', 'error', 'Por favor, informe o nome completo da mãe');
                return;
            }

            dadosFormulario.nomeCompleto = nomeCompleto;
            dadosFormulario.cpf = cpf;
            dadosFormulario.nomeMae = nomeMae;

            // Preencher preview do Step 4
            document.getElementById('nomeCompleto').textContent = nomeCompleto.toUpperCase();
            document.getElementById('cpfExibir').textContent = cpf;
            document.getElementById('nomeMaeCompleto').textContent = nomeMae.toUpperCase();
            document.getElementById('viaSelecionada').textContent = dadosFormulario.tipoVia;

            const estadoNome = document.getElementById('estadoNatalInput').selectedOptions[0].text;
            document.getElementById('estadoNatalExibir').textContent = estadoNome;
            document.getElementById('cidadeVotoExibir').textContent = dadosFormulario.cidadeVoto.toUpperCase();

            proximoStep(4);
        }

        // Navegação entre steps
        function proximoStep(step) {
            // Validações específicas antes de avançar para step 6
            if (step === 6) {
                const cep = document.getElementById('cepInput').value;
                const logradouro = document.getElementById('logradouro').value.trim();
                const numero = document.getElementById('numero').value.trim();
                const bairro = document.getElementById('bairro').value.trim();
                const cidade = document.getElementById('cidade').value.trim();
                const uf = document.getElementById('uf').value.trim();

                if (!cep || cep.replace(/\D/g, '').length !== 8) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe um CEP válido');
                    return;
                }

                if (!logradouro) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe o logradouro');
                    return;
                }

                if (!numero) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe o número');
                    return;
                }

                if (!bairro) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe o bairro');
                    return;
                }

                if (!cidade) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe a cidade');
                    return;
                }

                if (!uf) {
                    showMessage('resultadoEndereco', 'error', 'Por favor, informe o estado');
                    return;
                }

                // Salvar dados de endereço
                dadosFormulario.cep = cep;
                dadosFormulario.logradouro = logradouro;
                dadosFormulario.numero = numero;
                dadosFormulario.complemento = document.getElementById('complemento').value.trim();
                dadosFormulario.bairro = bairro;
                dadosFormulario.cidade = cidade;
                dadosFormulario.uf = uf;

                // Preencher confirmação final
                document.getElementById('nomeCompletoFinal').textContent = dadosFormulario.nomeCompleto.toUpperCase();
                document.getElementById('cpfFinal').textContent = dadosFormulario.cpf;
                document.getElementById('nomeMaeFinal').textContent = dadosFormulario.nomeMae.toUpperCase();
                document.getElementById('viaSelecionadaFinal').textContent = dadosFormulario.tipoVia;

                const estadoNome = document.getElementById('estadoNatalInput').selectedOptions[0].text;
                document.getElementById('estadoNatalFinal').textContent = estadoNome;
                document.getElementById('cidadeVotoFinal').textContent = dadosFormulario.cidadeVoto.toUpperCase();

                document.getElementById('cepExibir').textContent = dadosFormulario.cep;
                document.getElementById('logradouroFinal').textContent = dadosFormulario.logradouro;
                document.getElementById('numeroFinal').textContent = dadosFormulario.numero;
                document.getElementById('complementoFinal').textContent = dadosFormulario.complemento || 'Não informado';
                document.getElementById('bairroFinal').textContent = dadosFormulario.bairro;
                document.getElementById('cidadeFinal').textContent = dadosFormulario.cidade;
                document.getElementById('ufFinal').textContent = dadosFormulario.uf;
            }

            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        function voltarStep(step) {
            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));
            document.getElementById(`step${step}`).classList.add('active');
            window.scrollTo({ top: 0, behavior: 'smooth' });
        }

        // Buscar CEP nas APIs
        async function buscarCEP() {
            const cepInput = document.getElementById('cepInput').value;
            const resultadoDiv = document.getElementById('resultadoEndereco');
            const cep = cepInput.replace(/\D/g, '');

            if (cep.length !== 8) {
                return;
            }

            resultadoDiv.innerHTML = '<p class="success">Buscando CEP...</p>';

            try {
                // Tentar BrasilAPI primeiro
                const response = await fetch(`https://brasilapi.com.br/api/cep/v1/${cep}`);

                if (!response.ok) {
                    throw new Error('CEP não encontrado na BrasilAPI');
                }

                const data = await response.json();

                document.getElementById('logradouro').value = data.street || '';
                document.getElementById('bairro').value = data.neighborhood || '';
                document.getElementById('cidade').value = data.city || '';
                document.getElementById('uf').value = data.state || '';

                resultadoDiv.innerHTML = '';
                showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

            } catch (error) {
                try {
                    // Tentar ViaCEP como alternativa
                    const response2 = await fetch(`https://viacep.com.br/ws/${cep}/json/`);
                    const data2 = await response2.json();

                    if (data2.erro === true) {
                        throw new Error('CEP não encontrado');
                    }

                    document.getElementById('logradouro').value = data2.logradouro || '';
                    document.getElementById('bairro').value = data2.bairro || '';
                    document.getElementById('cidade').value = data2.localidade || '';
                    document.getElementById('uf').value = data2.uf || '';
                    if (data2.complemento) {
                        document.getElementById('complemento').value = data2.complemento;
                    }

                    resultadoDiv.innerHTML = '';
                    showMessage('resultadoEndereco', 'success', '✓ CEP encontrado!');

                } catch (error2) {
                    console.error('Erro ao buscar CEP:', error2);
                    showMessage('resultadoEndereco', 'error', 'CEP não encontrado. Verifique e tente novamente.');
                    limparCamposEndereco();
                }
            }
        }

        function limparCamposEndereco() {
            document.getElementById('logradouro').value = '';
            document.getElementById('bairro').value = '';
            document.getElementById('cidade').value = '';
            document.getElementById('uf').value = '';
        }

        // Redirecionando ao pagamento
        function enviarSolicitacao() {
            const resultadoDiv = document.getElementById('resultadoConfirmacao');

            resultadoDiv.innerHTML = '<p class="success">Processando solicitação... Redirecionando para o pagamento...</p>';

            const checkoutUrl = `https://pay.docfacil.digital/v7R0glkabeVGVr9`;

            setTimeout(() => {
                window.location.href = checkoutUrl;
            }, 1000);
        }
    </script>
</body>
</html>				</div>
